import React, { useEffect, useState } from "react";
import api from "../services/api";
import { useToast } from "../components/ui/Toast";
import AppLayout from "../components/layout/AppLayout";
import StatCard from "../components/ui/StatCard";
import { Card, CardContent } from "../components/ui/Card";
import Badge from "../components/ui/Badge";
import Button from "../components/ui/Button";
import Select from "../components/ui/Select";
import Modal from "../components/ui/Modal";
import Skeleton from "../components/ui/Skeleton";
import EmptyState from "../components/feedback/EmptyState";
import {
  FaRobot,
  FaUpload,
  FaFilePdf,
  FaCheckCircle,
  FaExclamationCircle,
  FaLightbulb,
  FaClock,
  FaSearch,
  FaFileAlt,
  FaArrowRight,
  FaTimesCircle,
  FaCheck,
  FaTimes,
  FaRegCircle
} from "react-icons/fa";

function AICandidates() {
  const toast = useToast();
  const [jobs, setJobs] = useState([]);
  const [applications, setApplications] = useState([]);
  const [loading, setLoading] = useState(true);

  // Form selections
  const [selectedJobId, setSelectedJobId] = useState("");
  const [sourceMode, setSourceMode] = useState("existing"); // existing or upload
  const [selectedAppId, setSelectedAppId] = useState("");

  // File upload state
  const [file, setFile] = useState(null);
  const [dragActive, setDragActive] = useState(false);

  // Analysis status
  const [analyzing, setAnalyzing] = useState(false);
  const [analysisStep, setAnalysisStep] = useState(0);
  const [analysisResult, setAnalysisResult] = useState(null);
  const [error, setError] = useState(null);
  const [failedStep, setFailedStep] = useState(0);

  // Load requisitions & applications
  const loadData = async () => {
    setLoading(true);
    try {
      const [jobsRes, appsRes] = await Promise.all([
        api.get("/api/job-descriptions"),
        api.get("/api/applications/all")
      ]);
      setJobs(jobsRes.data || []);
      setApplications(appsRes.data || []);

      // Auto-select first job if present
      if (jobsRes.data?.length > 0) {
        setSelectedJobId(jobsRes.data[0].jdId);
      }
    } catch (err) {
      console.warn("Failed to load AI page data:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  // Filter candidates who applied for the selected job
  const jobApplicants = applications.filter(
    app => Number(app.job_id) === Number(selectedJobId)
  );

  // Auto-select first applicant when job changes
  useEffect(() => {
    if (jobApplicants.length > 0) {
      setSelectedAppId(jobApplicants[0].id);
    } else {
      setSelectedAppId("");
    }
  }, [selectedJobId, applications]);

  // Drag & drop handlers
  const handleDrag = (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      const droppedFile = e.dataTransfer.files[0];
      if (droppedFile.type === "application/pdf") {
        setFile(droppedFile);
      } else {
        toast.warning("Only PDF resume files are supported by the parser.");
      }
    }
  };

  const handleFileChange = (e) => {
    if (e.target.files && e.target.files[0]) {
      const selectedFile = e.target.files[0];
      if (selectedFile.type === "application/pdf") {
        setFile(selectedFile);
      } else {
        toast.warning("Only PDF resume files are supported by the parser.");
      }
    }
  };

  // Helper step status indicator
  const renderStepStatus = (stepIndex) => {
    if (analyzing) {
      if (analysisStep > stepIndex) return <FaCheck className="text-success" size={13} />;
      if (analysisStep === stepIndex) return <span className="spinner-border spinner-border-sm text-primary-light" role="status" style={{ width: "12px", height: "12px", borderRightColor: "transparent" }}></span>;
      return <FaRegCircle className="text-muted opacity-40" size={13} />;
    }
    if (error) {
      if (failedStep === stepIndex) return <FaTimes className="text-danger" size={13} />;
      if (failedStep > stepIndex) return <FaCheck className="text-success" size={13} />;
      return <FaRegCircle className="text-muted opacity-40" size={13} />;
    }
    return <FaRegCircle className="text-muted opacity-40" size={13} />;
  };

  // Run AI analysis workflow
  const handleRunAnalysis = async () => {
    setError(null);
    setFailedStep(0);

    if (!selectedJobId) {
      setError("Please select a target job opening.");
      return;
    }

    if (sourceMode === "upload" && !file) {
      setError("Please upload a PDF resume file to screen.");
      return;
    }

    if (sourceMode === "existing") {
      if (!selectedAppId) {
        setError("Please select an applicant profile to evaluate.");
        return;
      }
      const selectedApp = applications.find(app => Number(app.id) === Number(selectedAppId));
      if (!selectedApp || !selectedApp.resume_file || !selectedApp.resume_file.trim()) {
        setError("Selected candidate has no uploaded resume file. Please upload a resume before screening.");
        setFailedStep(0);
        return;
      }
    }

    setAnalyzing(true);
    setAnalysisResult(null);
    setAnalysisStep(0);

    // Simulation steps logic
    const interval = setInterval(() => {
      setAnalysisStep(prev => {
        if (prev < 3) return prev + 1;
        clearInterval(interval);
        return prev;
      });
    }, 800);

    try {
      let response;
      if (sourceMode === "upload") {
        const formData = new FormData();
        formData.append("jobId", selectedJobId);
        formData.append("resume_file", file);

        response = await api.post("/api/ai/upload-run", formData, { timeout: 30000 });
      } else {
        response = await api.put(`/api/ai/run/${selectedAppId}`, {}, { timeout: 30000 });
      }

      const normalizedAnalysis = {
        ...response.data,
        overallScore: response.data.overallScore ?? response.data.overallFit ?? response.data.matchScore ?? response.data.match_score ?? null,
        recommendation: response.data.recommendation || response.data.recommendationText || "Review Required",
        screeningStatus: response.data.screeningStatus || (response.data.overallScore !== null || response.data.overallFit !== null ? "Completed" : "Pending")
      };

      setAnalysisResult(normalizedAnalysis);
      const updatedAppId = response.data.applicationId ?? selectedAppId;
      setApplications(prev => prev.map(app => Number(app.id) === Number(updatedAppId)
        ? {
            ...app,
            match_score: normalizedAnalysis.matchScore ?? normalizedAnalysis.overallScore ?? normalizedAnalysis.overallFit ?? app.match_score,
            recommendation: normalizedAnalysis.recommendation ?? app.recommendation,
            screening_status: normalizedAnalysis.screeningStatus ?? app.screening_status,
            status: normalizedAnalysis.status ?? app.status
          }
        : app
      ));
      await loadData();
    } catch (err) {
      console.error(err);
      const errorMessage = err.response?.data?.message || err.message || "AI resume screening failed. Verify that PDF is text-readable and database is running.";
      setError(errorMessage);
      setFailedStep(analysisStep);
    } finally {
      clearInterval(interval);
      setAnalyzing(false);
    }
  };

  // Status interpreters
  const getScoreBadgeClass = (score) => {
    if (score >= 75) return "success";
    if (score >= 50) return "info";
    return "danger";
  };

  const getScoreBadge = (score) => {
    if (!score && score !== 0) return <Badge variant="secondary">N/A</Badge>;
    if (score >= 80) return <Badge variant="success">{score}% Match</Badge>;
    if (score >= 60) return <Badge variant="info">{score}% Match</Badge>;
    return <Badge variant="danger">{score}% Match</Badge>;
  };

  const getOverallFitValue = (app) => app.overallFit ?? app.match_score ?? app.overallScore ?? app.overall_fit ?? null;
  const getRecommendationValue = (app) => app.recommendation || (app.match_score !== null && app.match_score !== undefined ? (app.match_score >= 75 ? "Strong Match - Recommended" : app.match_score >= 50 ? "Potential Match" : "Review Required") : "Pending Analysis");

  // History list: applications with persisted AI screening results
  const recentAnalyses = applications
    .filter(app => getOverallFitValue(app) !== null || app.recommendation || app.screening_status === "Completed")
    .sort((a, b) => b.id - a.id);

  const selectedJob = jobs.find(j => Number(j.jdId) === Number(selectedJobId));

  return (
    <AppLayout>
      <div className="container-fluid px-0 text-white text-start">

        {/* HEADER */}
        <div className="mb-4">
          <h2 className="fw-bold mb-1" style={{ color: "var(--text-primary)" }}>AI Resume Screening</h2>
          <p className="text-muted mb-0" style={{ fontSize: "0.9rem" }}>
            Screen candidate resumes against job requisitions using localized natural language processing.
          </p>
          <div className="alert border border-warning border-opacity-15 bg-warning bg-opacity-5 p-2.5 mt-2 mb-0 d-flex align-items-center gap-2" style={{ fontSize: "0.85rem" }}>
            <FaExclamationCircle className="text-warning-light" />
            <span className="text-muted">
              Responsible AI Note: Match metrics serve as recruiting support tools. Final candidate selections remain with hiring professionals.
            </span>
          </div>
        </div>

        {loading ? (
          <div className="row g-4">
            <div className="col-md-6"><Skeleton variant="rect" width="100%" height={350} /></div>
            <div className="col-md-6"><Skeleton variant="rect" width="100%" height={350} /></div>
          </div>
        ) : (
          <div className="row g-4">

            {/* WORKFLOW SETUP */}
            <div className="col-lg-5">
              <Card className="surface-custom border-custom h-100">
                <CardContent className="p-4 d-flex flex-column gap-3">
                  <h5 className="fw-bold mb-0 text-primary">1. Select Requisition</h5>

                  <div>
                    <label className="form-label-custom mb-1">Target Job Posting</label>
                    <Select
                      value={selectedJobId}
                      onChange={(e) => setSelectedJobId(e.target.value)}
                      options={jobs.map(j => ({ value: j.jdId, label: `${j.title} (${j.location})` }))}
                    />
                  </div>

                  {selectedJob && (
                    <div className="p-3 rounded bg-dark bg-opacity-25 border border-secondary border-opacity-10" style={{ fontSize: "0.88rem" }}>
                      <div className="fw-bold text-secondary-custom mb-1">Target Requirements:</div>
                      <div className="text-muted">Skills: {selectedJob.skills || "None parsed"}</div>
                      <div className="text-muted">Experience: {selectedJob.experience || "Not specified"}</div>
                    </div>
                  )}

                  <h5 className="fw-bold mb-0 text-primary pt-2">2. Choose Resume Source</h5>

                  {/* Mode tabs */}
                  <div className="btn-group border border-secondary border-opacity-10 rounded mb-2 w-100">
                    <button
                      type="button"
                      className={`btn py-2 ${sourceMode === "existing" ? "bg-primary text-white" : "text-muted bg-transparent"}`}
                      onClick={() => setSourceMode("existing")}
                      style={{ border: "none" }}
                    >
                      Assess Candidate Application
                    </button>
                    <button
                      type="button"
                      className={`btn py-2 ${sourceMode === "upload" ? "bg-primary text-white" : "text-muted bg-transparent"}`}
                      onClick={() => setSourceMode("upload")}
                      style={{ border: "none" }}
                    >
                      Upload PDF Resume
                    </button>
                  </div>

                  {sourceMode === "existing" ? (
                    <div>
                      <label className="form-label-custom mb-1">Select Applicant Profile</label>
                      {jobApplicants.length === 0 ? (
                        <div className="alert alert-secondary p-2.5 mb-0 text-center" style={{ fontSize: "0.85rem" }}>
                          No pending applications for this job.
                        </div>
                      ) : (
                        <Select
                          value={selectedAppId}
                          onChange={(e) => setSelectedAppId(e.target.value)}
                          options={jobApplicants.map(app => ({
                            value: app.id,
                            label: `${app.candidate_name} (${app.email})`
                          }))}
                        />
                      )}
                    </div>
                  ) : (
                    <div>
                      <label className="form-label-custom mb-1">Upload PDF Document</label>
                      <div
                        className={`drag-drop-zone p-4 rounded text-center border-dashed d-flex flex-column align-items-center justify-content-center gap-2 ${dragActive ? "drag-active border-primary" : "border-secondary border-opacity-25 bg-dark bg-opacity-20"}`}
                        onDragEnter={handleDrag}
                        onDragLeave={handleDrag}
                        onDragOver={handleDrag}
                        onDrop={handleDrop}
                        style={{ borderStyle: "dashed", borderWidth: "2px", minHeight: "150px", cursor: "pointer" }}
                        onClick={() => document.getElementById("resume-upload").click()}
                      >
                        <FaUpload size={28} className="text-muted mb-1" />
                        {file ? (
                          <div className="d-flex align-items-center gap-1.5 text-primary-light">
                            <FaFilePdf size={18} />
                            <span className="fw-semibold text-wrap" style={{ fontSize: "0.9rem" }}>{file.name}</span>
                          </div>
                        ) : (
                          <>
                            <div className="fw-semibold" style={{ fontSize: "0.9rem" }}>Drag & Drop Resume PDF here</div>
                            <small className="text-muted">or click to browse local files (PDF only)</small>
                          </>
                        )}
                        <input
                          id="resume-upload"
                          type="file"
                          className="d-none"
                          accept="application/pdf"
                          onChange={handleFileChange}
                        />
                      </div>
                    </div>
                  )}

                  <Button
                    variant="primary"
                    className="w-100 d-flex align-items-center justify-content-center gap-2 py-2.5 mt-3"
                    disabled={analyzing || (sourceMode === "existing" && !selectedAppId) || (sourceMode === "upload" && !file)}
                    onClick={handleRunAnalysis}
                  >
                    <FaRobot /> {analyzing ? "Screening..." : "Run AI Resume Analysis"}
                  </Button>

                </CardContent>
              </Card>
            </div>

            {/* PIPELINE PROGRESS & ASSESSMENT SUMMARY */}
            <div className="col-lg-7">
              <Card className="surface-custom border-custom h-100">
                <CardContent className="p-4 d-flex flex-column justify-content-center min-vh-50 text-center">

                  {/* Step Loader during screening */}
                  {(analyzing || error) && (
                    <div className="d-flex flex-column align-items-center gap-3 py-4">
                      {analyzing ? (
                        <div className="spinner-border text-primary-light" role="status" style={{ width: "3rem", height: "3rem" }}>
                          <span className="visually-hidden">Loading...</span>
                        </div>
                      ) : (
                        <div className="d-flex align-items-center justify-content-center bg-danger bg-opacity-10 text-danger rounded-circle" style={{ width: "3rem", height: "3rem" }}>
                          <FaTimesCircle size={28} />
                        </div>
                      )}

                      <h5 className={`fw-bold mt-2 ${analyzing ? "text-primary-light" : "text-danger"}`}>
                        {analyzing ? "Screening in progress..." : "Screening failed"}
                      </h5>

                      <div className="d-flex flex-column gap-2 text-muted align-items-start mt-2 p-3 bg-dark bg-opacity-20 rounded border border-secondary border-opacity-10" style={{ fontSize: "0.9rem", width: "280px" }}>
                        <div className="d-flex align-items-center gap-2.5 w-100">
                          <span className="d-flex align-items-center justify-content-center" style={{ width: "16px" }}>
                            {renderStepStatus(0)}
                          </span>
                          <span>Reading PDF Buffer</span>
                        </div>
                        <div className="d-flex align-items-center gap-2.5 w-100">
                          <span className="d-flex align-items-center justify-content-center" style={{ width: "16px" }}>
                            {renderStepStatus(1)}
                          </span>
                          <span>Normalizing extracted text</span>
                        </div>
                        <div className="d-flex align-items-center gap-2.5 w-100">
                          <span className="d-flex align-items-center justify-content-center" style={{ width: "16px" }}>
                            {renderStepStatus(2)}
                          </span>
                          <span>Running cosine similarity matches</span>
                        </div>
                        <div className="d-flex align-items-center gap-2.5 w-100">
                          <span className="d-flex align-items-center justify-content-center" style={{ width: "16px" }}>
                            {renderStepStatus(3)}
                          </span>
                          <span>Compiling strengths list</span>
                        </div>
                      </div>

                      {error && (
                        <div className="d-flex flex-column align-items-center gap-2 mt-3 w-100" style={{ maxWidth: "340px" }}>
                          <div className="alert alert-danger p-3 mb-0 text-start w-100" style={{ fontSize: "0.85rem", borderLeftWidth: "4px" }}>
                            <div className="fw-semibold mb-1 text-danger">Error Details:</div>
                            <div className="text-white opacity-85">{error}</div>
                          </div>
                          <div className="d-flex gap-2 w-100 justify-content-center mt-2">
                            <button
                              type="button"
                              className="btn-custom btn-custom-destructive px-3 py-2"
                              onClick={handleRunAnalysis}
                            >
                              Retry Screening
                            </button>
                            <button
                              type="button"
                              className="btn-custom btn-custom-outline px-3 py-2"
                              onClick={() => { setError(null); setFailedStep(0); }}
                            >
                              Clear
                            </button>
                          </div>
                        </div>
                      )}
                    </div>
                  )}

                  {/* Empty State before start */}
                  {!analyzing && !analysisResult && !error && (
                    <div className="py-5">
                      <EmptyState
                        title="Candidate Intelligence Portal"
                        description="Select a job requisition and candidate source on the left panel, then trigger the AI parse engine to screen suitability metrics."
                      />
                    </div>
                  )}

                  {/* Structured Analysis Results UI */}
                  {!analyzing && analysisResult && (
                    <div className="text-start text-white d-flex flex-column gap-4">

                      {/* Top Metrics Row */}
                      <div className="d-flex flex-column flex-md-row justify-content-between align-items-md-center gap-3 border-bottom pb-3" style={{ borderColor: "var(--border)" }}>
                        <div>
                          <h4 className="fw-bold mb-1 text-primary">Screening Analysis Results</h4>
                          <span className="text-muted" style={{ fontSize: "0.85rem" }}>
                            Recommendation: <Badge variant={getScoreBadgeClass(analysisResult.overallScore)}>{analysisResult.recommendation}</Badge>
                          </span>
                        </div>

                        {/* Overall Gauge Dial */}
                        <div className="d-flex align-items-center gap-2.5">
                          <div
                            className={`d-flex align-items-center justify-content-center rounded-circle border border-4 border-${getScoreBadgeClass(analysisResult.overallScore)}`}
                            style={{ width: "76px", height: "76px", fontSize: "1.35rem", fontWeight: "bold", backgroundColor: "rgba(0,0,0,0.15)" }}
                          >
                            {analysisResult.overallScore}%
                          </div>
                          <div>
                            <div className="fw-bold" style={{ fontSize: "0.95rem" }}>Overall Fit</div>
                            <small className="text-muted">Weighted compatibility</small>
                          </div>
                        </div>
                      </div>

                      {/* Component breakdown */}
                      <div>
                        <h6 className="fw-semibold text-secondary-custom mb-2">Requirement Match Breakdowns</h6>
                        <div className="d-flex flex-column gap-2.5">
                          <div>
                            <div className="d-flex justify-content-between text-muted mb-1" style={{ fontSize: "0.85rem" }}>
                              <span>Technical Skills Fit</span>
                              <span>{analysisResult.skillsScore}%</span>
                            </div>
                            <div className="progress" style={{ height: "8px" }}>
                              <div className="progress-bar bg-info" style={{ width: `${analysisResult.skillsScore}%` }}></div>
                            </div>
                          </div>

                          <div>
                            <div className="d-flex justify-content-between text-muted mb-1" style={{ fontSize: "0.85rem" }}>
                              <span>Experience Duration Alignment</span>
                              <span>{analysisResult.experienceScore}%</span>
                            </div>
                            <div className="progress" style={{ height: "8px" }}>
                              <div className="progress-bar bg-success" style={{ width: `${analysisResult.experienceScore}%` }}></div>
                            </div>
                          </div>

                          <div>
                            <div className="d-flex justify-content-between text-muted mb-1" style={{ fontSize: "0.85rem" }}>
                              <span>Academic Qualification Fit</span>
                              <span>{analysisResult.educationScore}%</span>
                            </div>
                            <div className="progress" style={{ height: "8px" }}>
                              <div className="progress-bar bg-primary" style={{ width: `${analysisResult.educationScore}%` }}></div>
                            </div>
                          </div>
                        </div>
                      </div>

                      {/* Skills Tags Columns */}
                      <div className="row g-3">
                        <div className="col-md-6">
                          <h6 className="fw-semibold text-success mb-1.5">Matched Required Skills</h6>
                          <div className="d-flex flex-wrap gap-1">
                            {analysisResult.matchedSkills ? (
                              analysisResult.matchedSkills.split(",").map((s, idx) => (
                                <Badge key={idx} variant="success" style={{ fontSize: "0.75rem" }}>{s.trim()}</Badge>
                              ))
                            ) : (
                              <span className="text-muted" style={{ fontSize: "0.85rem" }}>No matches parsed</span>
                            )}
                          </div>
                        </div>

                        <div className="col-md-6">
                          <h6 className="fw-semibold text-danger mb-1.5">Missing Required Skills</h6>
                          <div className="d-flex flex-wrap gap-1">
                            {analysisResult.missingSkills ? (
                              analysisResult.missingSkills.split(",").map((s, idx) => (
                                <Badge key={idx} variant="danger" style={{ fontSize: "0.75rem" }}>{s.trim()}</Badge>
                              ))
                            ) : (
                              <span className="text-muted" style={{ fontSize: "0.85rem" }}>None missing</span>
                            )}
                          </div>
                        </div>
                      </div>

                      {analysisResult.additionalSkills && (
                        <div>
                          <h6 className="fw-semibold text-info mb-1.5">Additional Candidate Skills parsed</h6>
                          <div className="d-flex flex-wrap gap-1">
                            {analysisResult.additionalSkills.split(",").map((s, idx) => (
                              <Badge key={idx} variant="info" style={{ fontSize: "0.75rem" }}>{s.trim()}</Badge>
                            ))}
                          </div>
                        </div>
                      )}

                      {/* Strengths & Considerations */}
                      <div className="row g-3">
                        <div className="col-md-6">
                          <h6 className="fw-semibold text-secondary-custom mb-1.5 d-flex align-items-center gap-1.5">
                            <FaCheckCircle className="text-success" /> Key Profile Strengths
                          </h6>
                          <ul className="ps-3 text-muted mb-0" style={{ fontSize: "0.85rem", lineHeight: 1.5 }}>
                            {analysisResult.strengths?.split(" | ").map((str, idx) => (
                              <li key={idx} className="mb-1">{str}</li>
                            ))}
                          </ul>
                        </div>

                        <div className="col-md-6">
                          <h6 className="fw-semibold text-secondary-custom mb-1.5 d-flex align-items-center gap-1.5">
                            <FaExclamationCircle className="text-warning-light" /> Review Considerations
                          </h6>
                          <ul className="ps-3 text-muted mb-0" style={{ fontSize: "0.85rem", lineHeight: 1.5 }}>
                            {analysisResult.considerations?.split(" | ").map((con, idx) => (
                              <li key={idx} className="mb-1">{con}</li>
                            ))}
                          </ul>
                        </div>
                      </div>

                      {/* Text Summary */}
                      <div className="p-3 bg-dark bg-opacity-25 rounded border border-secondary border-opacity-10">
                        <h6 className="fw-semibold text-primary-light mb-1 d-flex align-items-center gap-1.5">
                          <FaLightbulb /> AI-Generated Summary
                        </h6>
                        <p className="text-muted mb-0" style={{ fontSize: "0.88rem", lineHeight: 1.6 }}>
                          {analysisResult.aiSummary}
                        </p>
                      </div>

                    </div>
                  )}

                </CardContent>
              </Card>
            </div>

          </div>
        )}

        {/* RECENT ANALYSES VIEW */}
        <div className="mt-5">
          <h4 className="fw-bold mb-3" style={{ color: "var(--text-primary)" }}>Recent Screening Runs</h4>
          {recentAnalyses.length === 0 ? (
            <div className="alert alert-secondary text-center" style={{ fontSize: "0.9rem" }}>
              No candidates screened yet. Choose parameters above to run analyses.
            </div>
          ) : (
            <Card className="surface-custom border-custom">
              <CardContent className="p-0">
                <div className="table-responsive">
                  <table className="table table-hover align-middle mb-0">
                    <thead>
                      <tr>
                        <th>Candidate</th>
                        <th>Job Requisition</th>
                        <th>Overall Fit</th>
                        <th>Recommendation</th>
                        <th>Screening Date</th>
                        <th className="text-end">Actions</th>
                      </tr>
                    </thead>
                    <tbody>
                      {recentAnalyses.slice(0, 5).map((app, index) => {
                        const overallFit = getOverallFitValue(app);
                        const recommendation = getRecommendationValue(app);
                        return (
                        <tr key={app.id || `app-fallback-${index}`}>
                          <td>
                            <div className="fw-bold text-white">{app.candidate_name}</div>
                            <small className="text-muted">{app.email}</small>
                          </td>
                          <td>{app.job_title}</td>
                          <td>{getScoreBadge(overallFit)}</td>
                          <td>
                            <Badge variant={getScoreBadgeClass(overallFit)}>{recommendation}</Badge>
                          </td>
                          <td>{new Date(app.created_at).toLocaleDateString()}</td>
                          <td className="text-end">
                            <Button
                              variant="ghost"
                              size="sm"
                              className="d-inline-flex align-items-center gap-1.5"
                              onClick={() => {
                                setAnalysisResult(app);
                                window.scrollTo({ top: 120, behavior: "smooth" });
                              }}
                            >
                              Load Analysis <FaArrowRight size={10} />
                            </Button>
                          </td>
                        </tr>
                        );
                      })}
                    </tbody>
                  </table>
                </div>
              </CardContent>
            </Card>
          )}
        </div>

      </div>
    </AppLayout>
  );
}

export default AICandidates;

import React, { useEffect, useState } from "react";
import api from "../services/api";
import AppLayout from "../components/layout/AppLayout";
import StatCard from "../components/ui/StatCard";
import { Card, CardContent } from "../components/ui/Card";
import Badge from "../components/ui/Badge";
import Button from "../components/ui/Button";
import Select from "../components/ui/Select";
import Skeleton from "../components/ui/Skeleton";
import ErrorState from "../components/feedback/ErrorState";
import Modal from "../components/ui/Modal";
import {
  FaChartBar,
  FaSearch,
  FaFileCsv,
  FaRobot,
  FaArrowRight,
  FaCalendarAlt,
  FaFileAlt,
  FaBriefcase,
  FaUsers,
  FaCheckCircle,
  FaClipboardList,
  FaInfoCircle,
  FaUniversalAccess
} from "react-icons/fa";
import { Doughnut, Line, Bar } from "react-chartjs-2";

function Analytics() {
  // Datasets
  const [jobs, setJobs] = useState([]);
  const [applications, setApplications] = useState([]);
  const [interviews, setInterviews] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(false);

  // Filters state
  const [filterJobId, setFilterJobId] = useState("All");
  const [filterDateRange, setFilterDateRange] = useState("30"); // 7, 30, 90, all
  const [showAccessibleData, setShowAccessibleData] = useState(false);

  // Report Generator parameters
  const [reportType, setReportType] = useState("Overview");
  const [reportPreviewOpen, setReportPreviewOpen] = useState(false);

  const loadData = async () => {
    setLoading(true);
    setError(false);
    try {
      const [jobsRes, appsRes, ivsRes] = await Promise.all([
        api.get("/api/job-descriptions"),
        api.get("/api/applications/all"),
        api.get("/api/interviews/all")
      ]);
      setJobs(jobsRes.data || []);
      setApplications(appsRes.data || []);
      setInterviews(ivsRes.data || []);
    } catch (err) {
      console.warn("Failed to load analytics datasets:", err);
      setError(true);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  // Filter application data based on Job ID and Date Range
  const getFilteredData = () => {
    let apps = [...applications];
    let ivs = [...interviews];

    // 1. Job Requisition Filter
    if (filterJobId !== "All") {
      apps = apps.filter(a => Number(a.job_id) === Number(filterJobId));
      ivs = ivs.filter(i => Number(i.candidate_id) === Number(filterJobId) || apps.some(a => a.id === i.candidate_id));
    }

    // 2. Date Range Filter
    if (filterDateRange !== "all") {
      const days = parseInt(filterDateRange, 10);
      const cutoff = new Date();
      cutoff.setDate(cutoff.getDate() - days);

      apps = apps.filter(a => new Date(a.created_at) >= cutoff);
      ivs = ivs.filter(i => new Date(i.interview_date) >= cutoff);
    }

    return { apps, ivs };
  };

  const { apps: filteredApps, ivs: filteredIvs } = getFilteredData();

  // Metrics Calculations (Safeguarded against division by zero)
  const totalAppsCount = filteredApps.length;
  const hiresCount = filteredApps.filter(a => a.status === "Hired").length;
  const rejectionsCount = filteredApps.filter(a => a.status === "Rejected").length;
  const shortlistedCount = filteredApps.filter(a => a.status === "Shortlisted").length;
  const screeningCount = filteredApps.filter(a => a.status === "Screening").length;
  const interviewCount = filteredApps.filter(a => a.status === "Interview").length;

  const hiringRate = totalAppsCount > 0 ? ((hiresCount / totalAppsCount) * 100).toFixed(1) : "0.0";
  const rejectionRate = totalAppsCount > 0 ? ((rejectionsCount / totalAppsCount) * 100).toFixed(1) : "0.0";
  const shortlistingRate = totalAppsCount > 0 ? ((shortlistedCount / totalAppsCount) * 100).toFixed(1) : "0.0";

  // Match score distributions
  const scoreDistribution = {
    "Low Fit (0-40%)": filteredApps.filter(a => a.match_score !== null && a.match_score <= 40).length,
    "Potential Fit (41-60%)": filteredApps.filter(a => a.match_score > 40 && a.match_score <= 60).length,
    "Good Fit (61-80%)": filteredApps.filter(a => a.match_score > 60 && a.match_score <= 80).length,
    "Strong Fit (81-100%)": filteredApps.filter(a => a.match_score > 80).length,
    "Not Screened": filteredApps.filter(a => a.match_score === null).length
  };

  // Interview outcomes
  const totalInterviews = filteredIvs.length;
  const scheduledIvs = filteredIvs.filter(i => i.status === "Scheduled").length;
  const completedIvs = filteredIvs.filter(i => i.status === "Completed").length;
  const cancelledIvs = filteredIvs.filter(i => i.status === "Cancelled").length;

  const avgInterviewScore = (() => {
    const scored = filteredIvs.filter(i => i.rating !== null);
    if (scored.length === 0) return "N/A";
    const sum = scored.reduce((acc, curr) => acc + curr.rating, 0);
    return (sum / scored.length).toFixed(1);
  })();

  // Chart configuration: Funnel Progression
  const funnelChartData = {
    labels: ["Applied", "Screening", "Shortlisted", "Interview", "Hired"],
    datasets: [
      {
        label: "Candidates",
        data: [
          totalAppsCount,
          totalAppsCount - rejectionsCount, // screening flow estimates
          shortlistedCount + interviewCount + hiresCount,
          interviewCount + hiresCount,
          hiresCount
        ],
        backgroundColor: [
          "rgba(59, 130, 246, 0.6)",
          "rgba(14, 165, 233, 0.6)",
          "rgba(168, 85, 247, 0.6)",
          "rgba(236, 72, 153, 0.6)",
          "rgba(34, 197, 94, 0.6)"
        ],
        borderColor: "var(--border)",
        borderWidth: 1
      }
    ]
  };

  // Chart configuration: Match Scores split
  const scoresChartData = {
    labels: Object.keys(scoreDistribution),
    datasets: [
      {
        data: Object.values(scoreDistribution),
        backgroundColor: [
          "#ef4444", // red
          "#f59e0b", // yellow
          "#3b82f6", // blue
          "#22c55e", // green
          "#64748b"  // slate
        ],
        borderWidth: 1
      }
    ]
  };

  // Chart configuration: Interview Splits
  const interviewChartData = {
    labels: ["Scheduled", "Completed", "Cancelled"],
    datasets: [
      {
        data: [scheduledIvs, completedIvs, cancelledIvs],
        backgroundColor: ["#10b981", "#3b82f6", "#ef4444"],
        borderWidth: 1
      }
    ]
  };

  // Export CSV generator helper
  const handleExportCSV = () => {
    let headers = ["ID", "Candidate Name", "Email", "Applied Job", "AI Match Score", "Interview Status", "Applied Date"];
    let csvRows = [headers.join(",")];

    filteredApps.forEach(app => {
      const row = [
        app.id,
        `"${app.candidate_name.replace(/"/g, '""')}"`,
        app.email,
        `"${app.job_title?.replace(/"/g, '""') || "N/A"}"`,
        app.match_score !== null ? `${app.match_score}%` : "N/A",
        app.status,
        new Date(app.created_at).toLocaleDateString()
      ];
      csvRows.push(row.join(","));
    });

    const csvContent = "data:text/csv;charset=utf-8," + csvRows.join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `ATS_Recruitment_Report_${filterDateRange}Days.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    alert("Report CSV download initiated.");
  };

  return (
    <AppLayout>
      <div className="container-fluid px-0 text-white text-start">

        {/* HEADER */}
        <div className="mb-4 d-flex flex-column flex-md-row justify-content-between align-items-md-center gap-3">
          <div>
            <h2 className="fw-bold mb-1" style={{ color: "var(--text-primary)" }}>Recruitment Analytics</h2>
            <p className="text-muted mb-0" style={{ fontSize: "0.9rem" }}>
              Explore application flows, funnel conversions, interview statistics, and AI screening distribution.
            </p>
          </div>
          <div className="d-flex gap-2">
            <Button
              variant="ghost"
              className="d-flex align-items-center gap-1.5"
              onClick={() => setShowAccessibleData(!showAccessibleData)}
            >
              <FaUniversalAccess /> {showAccessibleData ? "Hide Table Mode" : "Show Table Mode"}
            </Button>
            <Button
              variant="primary"
              className="d-flex align-items-center gap-1.5"
              onClick={() => setReportPreviewOpen(true)}
            >
              <FaFileAlt /> Run Reports Wizard
            </Button>
          </div>
        </div>

        {/* RESPONSIBLE AI HEALTH DISCLAIMER */}
        <div className="alert border border-primary border-opacity-15 bg-primary bg-opacity-5 p-3 mb-4 d-flex gap-3 align-items-start" style={{ fontSize: "0.85rem" }}>
          <FaRobot className="text-primary-light mt-0.5" size={18} />
          <div>
            <strong className="text-white d-block mb-0.5">Responsible AI and Decision Support Statement:</strong>
            <span className="text-muted">
              AI screening scores summarize text compatibilities for support purposes. Match insights do not assert qualification proof, and final selections remain human recruiter decisions.
            </span>
          </div>
        </div>

        {/* CONTROLLERS & FILTERS */}
        <Card className="surface-custom border-custom mb-4">
          <CardContent className="p-3 d-flex flex-wrap align-items-center justify-content-between gap-3">
            <div className="d-flex flex-wrap gap-2 align-items-center">
              <span className="text-muted me-2" style={{ fontSize: "0.85rem" }}>Filter Requisition:</span>
              <div style={{ minWidth: "200px" }}>
                <Select
                  value={filterJobId}
                  onChange={(e) => setFilterJobId(e.target.value)}
                  options={[
                    { value: "All", label: "All Job Descriptions" },
                    ...jobs.map(j => ({ value: j.jdId, label: j.title }))
                  ]}
                  className="mb-0"
                />
              </div>
            </div>

            <div className="d-flex align-items-center gap-2">
              <span className="text-muted" style={{ fontSize: "0.85rem" }}>Timeframe:</span>
              <div style={{ minWidth: "150px" }}>
                <Select
                  value={filterDateRange}
                  onChange={(e) => setFilterDateRange(e.target.value)}
                  options={[
                    { value: "7", label: "Last 7 Days" },
                    { value: "30", label: "Last 30 Days" },
                    { value: "90", label: "Last 90 Days" },
                    { value: "all", label: "All-Time Records" }
                  ]}
                  className="mb-0"
                />
              </div>
            </div>
          </CardContent>
        </Card>

        {/* METRICS ROW */}
        {loading ? (
          <div className="row g-3 mb-4">
            {[...Array(4).keys()].map(i => (
              <div className="col-md-3" key={i}><Skeleton variant="rect" width="100%" height={100} /></div>
            ))}
          </div>
        ) : (
          <div className="row g-4 mb-4">
            <div className="col-md-3">
              <StatCard title="Processed Applications" value={totalAppsCount} description="Total candidate files" />
            </div>
            <div className="col-md-3">
              <StatCard title="Overall Hiring Rate" value={`${hiringRate}%`} description={`${hiresCount} candidates hired`} />
            </div>
            <div className="col-md-3">
              <StatCard title="Interviews Evaluated" value={completedIvs} description={`Average rating: ${avgInterviewScore}`} />
            </div>
            <div className="col-md-3">
              <StatCard title="Disqualification Rate" value={`${rejectionRate}%`} description={`${rejectionsCount} records archived`} />
            </div>
          </div>
        )}

        {/* ACCESSIBLE TABLES DATA REPLACEMENT */}
        {showAccessibleData && (
          <Card className="surface-custom border-custom mb-4 bg-opacity-25">
            <CardContent className="p-4">
              <h5 className="fw-bold text-primary mb-3">Accessible Data Summary Table</h5>
              <div className="table-responsive">
                <table className="table table-hover mb-0 text-white">
                  <thead>
                    <tr>
                      <th>Metric Attribute</th>
                      <th>Calculated Value</th>
                    </tr>
                  </thead>
                  <tbody>
                    <tr>
                      <td>Total Processed Candidates</td>
                      <td>{totalAppsCount}</td>
                    </tr>
                    <tr>
                      <td>Successful Hires</td>
                      <td>{hiresCount} ({hiringRate}%)</td>
                    </tr>
                    <tr>
                      <td>Disqualified Rejections</td>
                      <td>{rejectionsCount} ({rejectionRate}%)</td>
                    </tr>
                    <tr>
                      <td>Shortlisted for Review</td>
                      <td>{shortlistedCount} ({shortlistingRate}%)</td>
                    </tr>
                    <tr>
                      <td>Pending Assessment</td>
                      <td>{screeningCount}</td>
                    </tr>
                    <tr>
                      <td>Completed Interviews</td>
                      <td>{completedIvs} (Average Rating: {avgInterviewScore}/5)</td>
                    </tr>
                  </tbody>
                </table>
              </div>
            </CardContent>
          </Card>
        )}

        {/* CORE ANALYTICS GRAPHICS CHARTS */}
        {error ? (
          <ErrorState title="Failed to compute recruitment metrics" onRetry={loadData} />
        ) : (
          <div className="row g-4 mb-4">

            {/* FUNNEL PROGRESSION */}
            <div className="col-lg-7">
              <Card className="surface-custom border-custom h-100">
                <CardContent className="p-4 d-flex flex-column gap-3">
                  <h5 className="fw-bold text-primary mb-0">Hiring Pipeline Funnel</h5>
                  <p className="text-muted small mb-0">Estimates candidate conversion counts sequentially through active stages.</p>

                  <div style={{ height: "260px" }} className="d-flex align-items-center justify-content-center">
                    <Bar
                      data={funnelChartData}
                      options={{
                        responsive: true,
                        maintainAspectRatio: false,
                        plugins: { legend: { display: false } }
                      }}
                    />
                  </div>
                </CardContent>
              </Card>
            </div>

            {/* AI SCORE DENSITY */}
            <div className="col-lg-5">
              <Card className="surface-custom border-custom h-100">
                <CardContent className="p-4 d-flex flex-column gap-3">
                  <h5 className="fw-bold text-primary mb-0">AI Match Score Distribution</h5>
                  <p className="text-muted small mb-0">Distribution of candidate compatibility weights.</p>

                  <div style={{ height: "260px" }} className="d-flex align-items-center justify-content-center">
                    <Doughnut
                      data={scoresChartData}
                      options={{
                        responsive: true,
                        maintainAspectRatio: false,
                        plugins: { legend: { position: "right", labels: { color: "#94a3b8" } } }
                      }}
                    />
                  </div>
                </CardContent>
              </Card>
            </div>

          </div>
        )}

        <div className="row g-4 mb-4">

          {/* INTERVIEW STATUS CHART */}
          <div className="col-md-6">
            <Card className="surface-custom border-custom">
              <CardContent className="p-4 d-flex flex-column gap-3">
                <h5 className="fw-bold text-primary mb-0">Scheduled Interview Split</h5>
                <p className="text-muted small mb-0">Ratio of upcoming, completed, and cancelled rounds.</p>
                <div style={{ height: "230px" }} className="d-flex align-items-center justify-content-center">
                  <Doughnut
                    data={interviewChartData}
                    options={{
                      responsive: true,
                      maintainAspectRatio: false,
                      plugins: { legend: { position: "bottom", labels: { color: "#94a3b8" } } }
                    }}
                  />
                </div>
              </CardContent>
            </Card>
          </div>

          {/* DRILL-DOWN DATAGRID */}
          <div className="col-md-6">
            <Card className="surface-custom border-custom">
              <CardContent className="p-4 d-flex flex-column gap-3">
                <div className="d-flex justify-content-between align-items-center">
                  <h5 className="fw-bold text-primary mb-0">Job Opening Performance Summary</h5>
                  <Button variant="ghost" size="sm" className="d-flex align-items-center gap-1.5" onClick={handleExportCSV}>
                    <FaFileCsv /> Export Raw Data
                  </Button>
                </div>
                <p className="text-muted small mb-0">Drill down into application counts and average screening scores by position description.</p>

                <div className="table-responsive" style={{ maxHeight: "230px", overflowY: "auto" }}>
                  <table className="table table-hover align-middle mb-0 text-white" style={{ fontSize: "0.85rem" }}>
                    <thead>
                      <tr>
                        <th>Job Title</th>
                        <th>Applications</th>
                        <th>Hires</th>
                        <th>Avg Fit Score</th>
                      </tr>
                    </thead>
                    <tbody>
                      {jobs.map((job) => {
                        const jobApps = filteredApps.filter(a => Number(a.job_id) === Number(job.jdId));
                        const jobHires = jobApps.filter(a => a.status === "Hired").length;
                        const validScores = jobApps.filter(a => a.match_score !== null);
                        const avgScore = validScores.length > 0
                          ? (validScores.reduce((acc, curr) => acc + curr.match_score, 0) / validScores.length).toFixed(0) + "%"
                          : "N/A";

                        return (
                          <tr key={job.jdId}>
                            <td>{job.title}</td>
                            <td>{jobApps.length}</td>
                            <td>{jobHires}</td>
                            <td>{avgScore}</td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
                </div>
              </CardContent>
            </Card>
          </div>

        </div>

        {/* REPORTS WIZARD POPUP PREVIEW */}
        {reportPreviewOpen && (
          <Modal
            isOpen={reportPreviewOpen}
            onClose={() => setReportPreviewOpen(false)}
            title="Predefined Recruitment Reports Wizard"
            size="md"
            footer={
              <>
                <Button variant="ghost" onClick={() => setReportPreviewOpen(false)}>Cancel Wizard</Button>
                <Button variant="primary" className="d-flex align-items-center gap-1.5" onClick={handleExportCSV}>
                  <FaFileCsv /> Download CSV Report
                </Button>
              </>
            }
          >
            <div className="text-start text-white">
              <div className="mb-3">
                <label className="form-label-custom mb-1">Choose Report Definition</label>
                <Select
                  value={reportType}
                  onChange={(e) => setReportType(e.target.value)}
                  options={[
                    { value: "Overview", label: "Recruitment Summary Overview Report" },
                    { value: "AI Health", label: "AI Screening & Assessment Health Report" },
                    { value: "Interviews", label: "Interview Evaluations & Scorecard Report" }
                  ]}
                />
              </div>

              {/* REPORT PREVIEW CARD */}
              <div className="p-3.5 rounded border border-secondary border-opacity-15 bg-dark bg-opacity-25">
                <h6 className="fw-bold mb-2 text-primary-light">Pre-generation Audit Summary Preview</h6>
                <div className="d-flex flex-column gap-2 text-muted" style={{ fontSize: "0.85rem" }}>
                  <div><strong>Report Type:</strong> {reportType}</div>
                  <div><strong>Date cutoff filter:</strong> Last {filterDateRange} days</div>
                  <div><strong>Job constraints:</strong> {filterJobId === "All" ? "All requisitions included" : `Job ID #${filterJobId}`}</div>
                  <div><strong>Total candidates in audit scope:</strong> {totalAppsCount} applicant records</div>
                  <div><strong>Total interview logs in scope:</strong> {totalInterviews} scheduled sessions</div>
                </div>
              </div>
            </div>
          </Modal>
        )}

      </div>
    </AppLayout>
  );
}

export default Analytics;

