import React, { useEffect, useState } from "react";
import api from "../services/api";
import AppLayout from "../components/layout/AppLayout";
import { Card, CardContent } from "../components/ui/Card";
import Badge from "../components/ui/Badge";
import EmptyState from "../components/feedback/EmptyState";
import {
  FaCalendarAlt,
  FaVideo,
  FaFolderOpen
} from "react-icons/fa";

function InterviewStatus() {
  const [interviews, setInterviews] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchInterviews = async () => {
    setLoading(true);
    try {
      const email = localStorage.getItem("email");
      const response = await api.get(`/api/interviews/email/${email}`);
      setInterviews(response.data || []);
    } catch (error) {
      console.log("Failed to fetch candidate interview status logs:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchInterviews();
  }, []);

  const getBadge = (status) => {
    if (status === "Scheduled") return "success";
    if (status === "Completed") return "primary";
    return "danger";
  };

  return (
    <AppLayout>
      <div className="container-fluid px-0 text-white text-start">

        {/* HEADER */}
        <div className="mb-4">
          <h2 className="fw-bold mb-1" style={{ color: "var(--text-primary)" }}>My Interviews</h2>
          <p className="text-muted mb-0" style={{ fontSize: "0.9rem" }}>
            Track your upcoming scheduled interview rounds and virtual meeting details.
          </p>
        </div>

        {/* DETAILS TABLE */}
        <Card className="surface-custom border-custom">
          <CardContent className="p-0">
            {loading ? (
              <div className="py-5 text-center text-muted">Loading scheduled interview details...</div>
            ) : interviews.length === 0 ? (
              <div className="py-5 text-center text-muted d-flex flex-column align-items-center gap-2">
                <FaFolderOpen size={36} className="text-secondary opacity-30" />
                <span>No scheduled interviews found for your account.</span>
              </div>
            ) : (
              <div className="table-responsive">
                <table className="table table-hover align-middle mb-0 text-white">
                  <thead>
                    <tr className="table-dark">
                      <th>Round</th>
                      <th>Date</th>
                      <th>Time</th>
                      <th>Mode</th>
                      <th>Status</th>
                      <th>Meeting / Link</th>
                    </tr>
                  </thead>
                  <tbody>
                    {interviews.map((iv, index) => (
                      <tr key={iv.id || `iv-fallback-${index}`}>
                        <td>
                          <strong className="text-primary-light">{iv.round || "Technical Interview"}</strong>
                          <small className="text-muted d-block" style={{ fontSize: "0.75rem" }}>ID: #{iv.id}</small>
                        </td>
                        <td>{iv.interview_date ? new Date(iv.interview_date).toLocaleDateString() : "TBD"}</td>
                        <td>{iv.interview_time || "TBD"} ({iv.duration || 30} mins)</td>
                        <td>{iv.mode || iv.interview_mode || "Video Call"}</td>
                        <td>
                          <Badge variant={getBadge(iv.status)}>{iv.status}</Badge>
                        </td>
                        <td>
                          {iv.status === "Scheduled" && (iv.mode || iv.interview_mode) === "Video Call" && iv.meeting_link ? (
                            <a
                              href={iv.meeting_link}
                              target="_blank"
                              rel="noreferrer"
                              className="btn btn-sm btn-primary d-inline-flex align-items-center gap-1.5"
                              style={{ textDecoration: "none" }}
                            >
                              <FaVideo /> Join Meeting
                            </a>
                          ) : (
                            <span className="text-muted small">N/A</span>
                          )}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </CardContent>
        </Card>

      </div>
    </AppLayout>
  );
}

export default InterviewStatus;

import React, { useEffect, useState } from "react";
import { useLocation } from "react-router-dom";
import api from "../services/api";
import { useToast } from "../components/ui/Toast";
import AppLayout from "../components/layout/AppLayout";
import StatCard from "../components/ui/StatCard";
import { Card, CardContent } from "../components/ui/Card";
import Badge from "../components/ui/Badge";
import Button from "../components/ui/Button";
import Select from "../components/ui/Select";
import Modal from "../components/ui/Modal";
import Skeleton from "../components/ui/Skeleton";
import EmptyState from "../components/feedback/EmptyState";
import {
  FaCalendarAlt,
  FaSearch,
  FaFileDownload,
  FaRobot,
  FaCheck,
  FaTimes,
  FaUserCircle,
  FaClock,
  FaExchangeAlt,
  FaMapMarkerAlt,
  FaVideo,
  FaStar,
  FaFolderOpen,
  FaUsers
} from "react-icons/fa";
import Calendar from "react-calendar";
import "react-calendar/dist/Calendar.css";

// Form round types
const ROUND_OPTIONS = [
  { value: "Screening Interview", label: "Screening Interview" },
  { value: "Technical Interview", label: "Technical Interview" },
  { value: "Behavioral Interview", label: "Behavioral Interview" },
  { value: "HR Interview", label: "HR Interview" },
  { value: "Final Interview", label: "Final Interview" }
];

// Form modes
const MODE_OPTIONS = [
  { value: "Video Call", label: "Video Call" },
  { value: "Phone Call", label: "Phone Call" },
  { value: "In-Person", label: "In-Person" }
];

function Interviews() {
  const location = useLocation();
  const toast = useToast();
  const preselectedCandidate = location.state?.candidate || null;

  const [interviews, setInterviews] = useState([]);
  const [candidates, setCandidates] = useState([]);
  const [interviewers, setInterviewers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [filterStatus, setFilterStatus] = useState("All");

  // Scheduling Form state
  const [formCandidateId, setFormCandidateId] = useState("");
  const [formRound, setFormRound] = useState("Technical Interview");
  const [formMode, setFormMode] = useState("Video Call");
  const [formInterviewerId, setFormInterviewerId] = useState("");
  const [formDate, setFormDate] = useState("");
  const [formTime, setFormTime] = useState("");
  const [formDuration, setFormDuration] = useState("30");
  const [formMeetingLink, setFormMeetingLink] = useState("");
  const [scheduling, setScheduling] = useState(false);

  // Calendar state
  const [calendarDate, setCalendarDate] = useState(new Date());

  // Feedback/Scorecard modal state
  const [feedbackOpen, setFeedbackOpen] = useState(false);
  const [selectedIv, setSelectedIv] = useState(null);
  const [feedbackText, setFeedbackText] = useState("");
  const [ratingVal, setRatingVal] = useState("3");
  const [submittingFeedback, setSubmittingFeedback] = useState(false);

  const loadData = async () => {
    setLoading(true);
    try {
      const [ivsRes, appsRes, interviewersRes] = await Promise.all([
        api.get("/api/interviews/all"),
        api.get("/api/applications/all"),
        api.get("/api/team/interviewers").catch(() => ({ data: [] }))
      ]);
      setInterviews(ivsRes.data || []);
      setCandidates(appsRes.data || []);
      const fetchedInterviewers = interviewersRes.data || [];
      setInterviewers(fetchedInterviewers);

      // Pre-select first interviewer if available
      if (fetchedInterviewers.length > 0 && !formInterviewerId) {
        setFormInterviewerId(fetchedInterviewers[0].id);
      }

      // Pre-select applicant context if passed
      if (preselectedCandidate) {
        setFormCandidateId(preselectedCandidate.id);
      } else if (appsRes.data?.length > 0) {
        // Pre-select first eligible candidate
        const eligible = appsRes.data.filter(c => c.status !== "Rejected");
        if (eligible.length > 0) {
          setFormCandidateId(eligible[0].id);
        }
      }
    } catch (err) {
      console.warn("Failed to load interview dashboard datasets:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  // Filter candidates who are NOT rejected for scheduling dropdown
  const eligibleCandidates = candidates.filter(c => c.status !== "Rejected");

  // Create schedule workflow
  const handleScheduleInterview = async (e) => {
    e.preventDefault();
    if (!formCandidateId) {
      toast.warning("Please select a candidate requisition.");
      return;
    }
    if (!formDate) {
      toast.warning("Please select an interview date.");
      return;
    }
    if (!formTime) {
      toast.warning("Please select a start time.");
      return;
    }
    if (!formInterviewerId) {
      toast.warning("Please select an interviewer.");
      return;
    }

    const app = candidates.find(c => Number(c.id) === Number(formCandidateId));
    if (!app) {
      toast.error("Selected candidate application was not found.");
      return;
    }

    // Prevent past date scheduling
    const selectedDate = new Date(formDate + "T" + formTime);
    if (selectedDate < new Date()) {
      toast.warning("Interview date and time cannot be in the past.");
      return;
    }

    const selectedInterviewer = interviewers.find(iv => String(iv.id) === String(formInterviewerId));
    if (!selectedInterviewer) {
      toast.error("Selected interviewer was not found.");
      return;
    }

    setScheduling(true);
    try {
      const payload = {
        candidate_id: app.id,
        application_id: app.id,
        job_id: app.job_id ?? null,
        candidate_name: app.candidate_name,
        email: app.email,
        phone: app.phone || "N/A",
        ai_score: app.match_score || 0,
        interview_date: formDate,
        interview_time: formTime,
        mode: formMode,
        interviewer_id: selectedInterviewer.id,
        interviewer_name: selectedInterviewer.name,
        interviewer: selectedInterviewer.name,
        round: formRound,
        duration: formDuration,
        meeting_link: formMode === "Video Call" ? formMeetingLink : null
      };

      console.log("[Interviews] Scheduling payload:", payload);
      await api.post("/api/interviews", payload);
      toast.success("Interview scheduled successfully! Candidate status updated to 'Interview'.");

      // Clear form
      setFormMeetingLink("");
      setFormDate("");
      setFormTime("");
      setFormInterviewerId("");

      loadData();
    } catch (err) {
      console.error("[Interviews] Scheduling failed", {
        status: err.response?.status,
        message: err.response?.data?.message,
        errorCode: err.response?.data?.errorCode,
        data: err.response?.data
      });
      const backendMessage = err.response?.data?.message || err.response?.data?.error || "Failed to schedule interview. Please check for scheduling conflicts.";
      toast.error(backendMessage);
    } finally {
      setScheduling(false);
    }
  };

  // Reschedule/Cancel status actions
  const handleUpdateStatus = async (id, status) => {
    try {
      await api.put(`/api/interviews/status/${id}`, { status });
      toast.success(`Interview status updated to ${status}`);
      loadData();
    } catch (err) {
      const msg = err.response?.data?.message || "Failed to update interview status";
      toast.error(msg);
    }
  };

  // Feedback Submission Scorecard
  const triggerFeedback = (iv) => {
    setSelectedIv(iv);
    setFeedbackText("");
    setRatingVal("3");
    setFeedbackOpen(true);
  };

  const handleConfirmFeedback = async () => {
    if (!selectedIv) return;
    if (!feedbackText.trim()) {
      toast.warning("Please enter evaluation comments before completing the scorecard.");
      return;
    }

    setSubmittingFeedback(true);
    try {
      await api.put(`/api/interviews/feedback/${selectedIv.id}`, {
        feedback: feedbackText.trim(),
        rating: parseInt(ratingVal, 10)
      });
      toast.success("Scorecard and feedback evaluation logged successfully.");
      setFeedbackOpen(false);
      loadData();
    } catch (err) {
      const msg = err.response?.data?.message || "Failed to submit feedback";
      toast.error(msg);
    } finally {
      setSubmittingFeedback(false);
    }
  };

  // Filter list
  const filteredInterviews = interviews.filter(iv => {
    const matchesSearch =
      iv.candidate_name?.toLowerCase().includes(search.toLowerCase()) ||
      iv.email?.toLowerCase().includes(search.toLowerCase()) ||
      iv.interviewer?.toLowerCase().includes(search.toLowerCase()) ||
      iv.round?.toLowerCase().includes(search.toLowerCase());

    const matchesStatus = filterStatus === "All" ? true : iv.status === filterStatus;

    return matchesSearch && matchesStatus;
  });

  // Stats calculation
  const totalCount = interviews.length;
  const upcomingCount = interviews.filter(iv => iv.status === "Scheduled").length;
  const completedCount = interviews.filter(iv => iv.status === "Completed").length;
  const cancelledCount = interviews.filter(iv => iv.status === "Cancelled").length;

  // Status Badge Mapper
  const getBadge = (status) => {
    if (status === "Scheduled") return "success";
    if (status === "Completed") return "primary";
    return "danger";
  };

  return (
    <AppLayout>
      <div className="container-fluid px-0 text-white text-start">

        {/* HEADER */}
        <div className="mb-4">
          <h2 className="fw-bold mb-1" style={{ color: "var(--text-primary)" }}>Interview Management</h2>
          <p className="text-muted mb-0" style={{ fontSize: "0.9rem" }}>
            Schedule and conduct candidate evaluation rounds, submit structured scorecards, and check conflicts.
          </p>
        </div>

        {/* METRICS ROW */}
        <div className="row g-4 mb-4">
          <div className="col-6 col-md-3">
            <StatCard title="Upcoming Interviews" value={upcomingCount} icon={<FaCalendarAlt />} loading={loading} description="Booked calendar slots" />
          </div>
          <div className="col-6 col-md-3">
            <StatCard title="Evaluation Complete" value={completedCount} icon={<FaCheck />} loading={loading} description="Scorecards logged" />
          </div>
          <div className="col-6 col-md-3">
            <StatCard title="Cancelled Bookings" value={cancelledCount} icon={<FaTimes />} loading={loading} description="Rescheduled rounds" />
          </div>
          <div className="col-6 col-md-3">
            <StatCard title="Total Scheduled" value={totalCount} icon={<FaUsers />} loading={loading} description="Total metrics log" />
          </div>
        </div>

        <div className="row g-4">

          {/* LEFT COLUMN: SCHEDULE WIZARD & CALENDAR */}
          <div className="col-lg-5 d-flex flex-column gap-4">

            {/* CALENDAR */}
            <Card className="surface-custom border-custom">
              <CardContent className="p-3.5 d-flex flex-column align-items-center justify-content-center">
                <h5 className="fw-bold text-primary align-self-start mb-3">Interview Calendar</h5>
                <Calendar
                  value={calendarDate}
                  onChange={setCalendarDate}
                  className="bg-transparent border-0 w-100 text-white rounded"
                />
              </CardContent>
            </Card>

            {/* SCHEDULE WIZARD FORM */}
            <Card className="surface-custom border-custom">
              <CardContent className="p-4">
                <h5 className="fw-bold text-primary mb-3">Schedule New Round</h5>

                <form onSubmit={handleScheduleInterview} className="d-flex flex-column gap-3">
                  <div>
                    <label className="form-label-custom mb-1">Select Candidate Requisition</label>
                    <Select
                      value={formCandidateId}
                      onChange={(e) => setFormCandidateId(e.target.value)}
                      options={eligibleCandidates.map(c => ({
                        value: c.id,
                        label: `${c.candidate_name} — ${c.job_title}`
                      }))}
                    />
                  </div>

                  <div className="row g-3">
                    <div className="col-6">
                      <label className="form-label-custom mb-1">Interview Round</label>
                      <Select
                        value={formRound}
                        onChange={(e) => setFormRound(e.target.value)}
                        options={ROUND_OPTIONS}
                      />
                    </div>
                    <div className="col-6">
                      <label className="form-label-custom mb-1">Interview Type</label>
                      <Select
                        value={formMode}
                        onChange={(e) => setFormMode(e.target.value)}
                        options={MODE_OPTIONS}
                      />
                    </div>
                  </div>

                  <div className="row g-3">
                    <div className="col-6">
                      <label className="form-label-custom mb-1">Date</label>
                      <input
                        type="date"
                        className="form-control"
                        required
                        value={formDate}
                        onChange={(e) => setFormDate(e.target.value)}
                      />
                    </div>
                    <div className="col-6">
                      <label className="form-label-custom mb-1">Start Time</label>
                      <input
                        type="time"
                        className="form-control"
                        required
                        value={formTime}
                        onChange={(e) => setFormTime(e.target.value)}
                      />
                    </div>
                  </div>

                  <div className="row g-3">
                    <div className="col-6">
                      <label className="form-label-custom mb-1">Duration</label>
                      <Select
                        value={formDuration}
                        onChange={(e) => setFormDuration(e.target.value)}
                        options={[
                          { value: "15", label: "15 Minutes" },
                          { value: "30", label: "30 Minutes" },
                          { value: "45", label: "45/50 Minutes" },
                          { value: "60", label: "60 Minutes" }
                        ]}
                      />
                    </div>
                    <div className="col-6">
                      <label className="form-label-custom mb-1">Assigned Interviewer</label>
                      <Select
                        value={formInterviewerId}
                        onChange={(e) => setFormInterviewerId(e.target.value)}
                        options={
                          interviewers.length > 0
                            ? interviewers.map(iv => ({
                                value: iv.id,
                                label: `${iv.name} (${iv.role})`
                              }))
                            : [
                                { value: "", label: "No interviewers available" }
                              ]
                        }
                      />
                    </div>
                  </div>

                  {formMode === "Video Call" && (
                    <div>
                      <label className="form-label-custom mb-1">Meeting Link (e.g. Google Meet URL)</label>
                      <input
                        type="url"
                        className="form-control"
                        placeholder="https://meet.google.com/abc-defg-hij"
                        value={formMeetingLink}
                        onChange={(e) => setFormMeetingLink(e.target.value)}
                      />
                    </div>
                  )}

                  <Button
                    type="submit"
                    variant="primary"
                    loading={scheduling}
                    disabled={scheduling}
                    className="w-100 py-2.5 mt-2 d-flex align-items-center justify-content-center gap-1.5"
                  >
                    <FaCalendarAlt /> {scheduling ? "Scheduling..." : "Book Schedule Slot"}
                  </Button>
                </form>

              </CardContent>
            </Card>

          </div>

          {/* RIGHT COLUMN: BOOKINGS LIST & EVALUATIONS */}
          <div className="col-lg-7">
            <Card className="surface-custom border-custom h-100">
              <CardContent className="p-4 d-flex flex-column gap-3.5">
                <div className="d-flex flex-column flex-md-row justify-content-between align-items-md-center gap-3">
                  <h5 className="fw-bold text-primary mb-0">Interview Pipeline List</h5>

                  <div className="d-flex align-items-center gap-2">
                    <div style={{ minWidth: "120px" }}>
                      <Select
                        value={filterStatus}
                        onChange={(e) => setFilterStatus(e.target.value)}
                        options={[
                          { value: "All", label: "All Statuses" },
                          { value: "Scheduled", label: "Scheduled" },
                          { value: "Completed", label: "Completed" },
                          { value: "Cancelled", label: "Cancelled" }
                        ]}
                        className="mb-0"
                      />
                    </div>
                  </div>
                </div>

                <div className="position-relative">
                  <FaSearch className="position-absolute text-muted" style={{ left: "12px", top: "14px" }} />
                  <input
                    type="text"
                    className="form-control ps-5"
                    placeholder="Search candidate name, interviewer, round..."
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                  />
                </div>

                {/* LIST ROWS */}
                <div className="d-flex flex-column gap-3 overflow-y-auto pr-1" style={{ maxHeight: "700px" }}>
                  {filteredInterviews.length === 0 ? (
                    <div className="py-5 text-center text-muted small d-flex flex-column align-items-center gap-2">
                      <FaFolderOpen size={32} className="text-secondary opacity-30" />
                      <span>No scheduled bookings match your selectors.</span>
                    </div>
                  ) : (
                    filteredInterviews.map((iv, index) => (
                      <Card key={iv.id || `iv-fallback-${index}`} className="border-custom shadow-sm" style={{ backgroundColor: "rgba(30, 41, 59, 0.3)" }}>
                        <CardContent className="p-4 text-start">
                          <div className="d-flex justify-content-between align-items-start gap-2 mb-2">
                            <div>
                              <h6 className="fw-bold text-white mb-0.5">{iv.candidate_name}</h6>
                              <small className="text-muted d-block">{iv.email}</small>
                            </div>
                            <Badge variant={getBadge(iv.status)}>{iv.status}</Badge>
                          </div>

                          <div className="row g-2 text-muted mb-3.5" style={{ fontSize: "0.85rem" }}>
                            <div className="col-md-6">
                              <strong>Round:</strong> {iv.round || "Technical Interview"}
                            </div>
                            <div className="col-md-6">
                              <strong>Interviewer:</strong> {iv.interviewer || "Not assigned"}
                            </div>
                            <div className="col-md-6">
                              <strong>Schedule:</strong> {iv.interview_date ? new Date(iv.interview_date).toLocaleDateString() : "TBD"} at {iv.interview_time || "TBD"} ({iv.duration || 30} mins)
                            </div>
                            <div className="col-md-6">
                              <strong>Type/Mode:</strong> {iv.mode || "Video Call"}
                            </div>
                          </div>

                          {/* Meeting details */}
                          {iv.mode === "Video Call" && iv.meeting_link && (
                            <div className="p-2.5 rounded bg-dark bg-opacity-25 border border-secondary border-opacity-10 d-flex align-items-center justify-content-between mb-3.5" style={{ fontSize: "0.85rem" }}>
                              <span className="text-truncate text-muted me-2">Link: {iv.meeting_link}</span>
                              <a href={iv.meeting_link} target="_blank" rel="noreferrer" className="btn btn-sm btn-ghost p-1 text-primary-light d-flex align-items-center gap-1">
                                Join <FaVideo />
                              </a>
                            </div>
                          )}

                          {/* Evaluations block if completed */}
                          {iv.status === "Completed" && (
                            <div className="p-3 rounded bg-success bg-opacity-5 border border-success border-opacity-15 mb-3.5">
                              <div className="fw-bold text-success-light mb-1 d-flex align-items-center justify-content-between" style={{ fontSize: "0.85rem" }}>
                                <span>Scorecard Evaluation rating:</span>
                                <span className="d-flex align-items-center gap-1">
                                  {iv.rating} <FaStar className="text-warning-light" />
                                </span>
                              </div>
                              <p className="text-muted mb-0" style={{ fontSize: "0.85rem", lineHeight: 1.4 }}>{iv.feedback}</p>
                            </div>
                          )}

                          {/* Recruiter Actions */}
                          <div className="d-flex gap-2 justify-content-end border-top pt-3" style={{ borderColor: "rgba(255,255,255,0.05)" }}>
                            {iv.status === "Scheduled" && (
                              <>
                                <Button variant="destructive" size="sm" onClick={() => handleUpdateStatus(iv.id, "Cancelled")}>
                                  Cancel Booking
                                </Button>
                                <Button variant="primary" size="sm" onClick={() => triggerFeedback(iv)}>
                                  Evaluate & Submit Scorecard
                                </Button>
                              </>
                            )}
                          </div>

                        </CardContent>
                      </Card>
                    ))
                  )}
                </div>
              </CardContent>
            </Card>
          </div>

        </div>

        {/* FEEDBACK SCORECARD FORM MODAL */}
        {feedbackOpen && selectedIv && (
          <Modal
            isOpen={feedbackOpen}
            onClose={() => setFeedbackOpen(false)}
            title="Interview Evaluation Scorecard"
            size="sm"
            footer={
              <>
                <Button variant="ghost" onClick={() => setFeedbackOpen(false)}>Cancel</Button>
                <Button variant="primary" loading={submittingFeedback} onClick={handleConfirmFeedback}>
                  Submit Evaluation
                </Button>
              </>
            }
          >
            <div className="text-start text-white">
              <div className="mb-3">
                <span className="text-muted small">Candidate:</span>
                <div className="fw-bold">{selectedIv.candidate_name}</div>
                <small className="text-muted">{selectedIv.round} | Interviewer: {selectedIv.interviewer}</small>
              </div>

              <div className="mb-3">
                <label className="form-label-custom mb-1">Job Competency Scorecard Rating</label>
                <Select
                  value={ratingVal}
                  onChange={(e) => setRatingVal(e.target.value)}
                  options={[
                    { value: "5", label: "5 — Strongly Exceeds Expectations" },
                    { value: "4", label: "4 — Exceeds Expectations" },
                    { value: "3", label: "3 — Meets Expectations" },
                    { value: "2", label: "2 — Partially Meets Expectations" },
                    { value: "1", label: "1 — Does Not Meet Expectations" }
                  ]}
                />
              </div>

              <div>
                <label className="form-label-custom mb-1">Evaluation Assessment Feedback</label>
                <textarea
                  className="form-control"
                  rows="4"
                  placeholder="Record interview notes, technical competency feedback, role fits, or review suggestions..."
                  value={feedbackText}
                  onChange={(e) => setFeedbackText(e.target.value)}
                />
              </div>
            </div>
          </Modal>
        )}

      </div>
    </AppLayout>
  );
}

export default Interviews;

import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import api from "../services/api";
import AppLayout from "../components/layout/AppLayout";
import StatCard from "../components/ui/StatCard";
import { Card, CardContent } from "../components/ui/Card";
import Badge from "../components/ui/Badge";
import Button from "../components/ui/Button";
import Input from "../components/ui/Input";
import Select from "../components/ui/Select";
import Modal from "../components/ui/Modal";
import Skeleton from "../components/ui/Skeleton";
import EmptyState from "../components/feedback/EmptyState";
import HiringTeamManager from "../components/ui/HiringTeamManager";
import ErrorState from "../components/feedback/ErrorState";
import {
  FaBriefcase,
  FaMapMarkerAlt,
  FaMoneyBillWave,
  FaUsers,
  FaSearch,
  FaThLarge,
  FaList,
  FaTrashAlt,
  FaEdit,
  FaCopy,
  FaPlay,
  FaBan,
  FaPlus,
  FaEye,
  FaTimes
} from "react-icons/fa";

function Jobs() {
  const navigate = useNavigate();
  const recruiterRole = localStorage.getItem("role");

  // State Declarations
  const [jobs, setJobs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(false);
  const [viewMode, setViewMode] = useState("grid"); // grid or table

  // Search & Filter state
  const [search, setSearch] = useState("");
  const [filterStatus, setFilterStatus] = useState("All");
  const [filterLocation, setFilterLocation] = useState("All");
  const [sortBy, setSortBy] = useState("newest"); // newest, oldest, title-asc, title-desc

  // Pagination state
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 6;

  // Form Modal state
  const [modalOpen, setModalOpen] = useState(false);
  const [editingJob, setEditingJob] = useState(null);
  const [formLoading, setFormLoading] = useState(false);

  // Form fields
  const [title, setTitle] = useState("");
  const [skillsInput, setSkillsInput] = useState("");
  const [skillsList, setSkillsList] = useState([]);
  const [experience, setExperience] = useState("");
  const [salary, setSalary] = useState("");
  const [location, setLocation] = useState("");
  const [description, setDescription] = useState("");

  // Preview Modal state
  const [previewOpen, setPreviewOpen] = useState(false);

  // Delete Confirm Modal state
  const [deleteOpen, setDeleteOpen] = useState(false);
  const [jobToDelete, setJobToDelete] = useState(null);
  const [hiringTeamJob, setHiringTeamJob] = useState(null);

  const fetchJobs = async () => {
    setLoading(true);
    setError(false);
    try {
      const response = await api.get("/api/job-descriptions");
      setJobs(response.data || []);
    } catch (err) {
      console.warn("Failed to fetch jobs:", err);
      setError(true);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchJobs();
  }, []);

  // Form handlers
  const openCreateModal = () => {
    setEditingJob(null);
    setTitle("");
    setSkillsInput("");
    setSkillsList([]);
    setExperience("");
    setSalary("");
    setLocation("");
    setDescription("");
    setModalOpen(true);
  };

  const openEditModal = (job) => {
    setEditingJob(job);
    setTitle(job.title || "");
    setSkillsList(job.skills ? job.skills.split(",").map(s => s.trim()) : []);
    setSkillsInput("");
    setExperience(job.experience || "");
    setSalary(job.salary || "");
    setLocation(job.location || "");
    setDescription(job.description || "");
    setModalOpen(true);
  };

  const handleAddSkill = (e) => {
    if (e.key === "Enter" || e.type === "click") {
      if (e.key === "Enter") e.preventDefault();
      const val = skillsInput.trim();
      if (val && !skillsList.includes(val)) {
        setSkillsList([...skillsList, val]);
        setSkillsInput("");
      }
    }
  };

  const handleRemoveSkill = (skillToRemove) => {
    setSkillsList(skillsList.filter(s => s !== skillToRemove));
  };

  const handleSaveJob = async () => {
    if (!title.trim() || !description.trim() || skillsList.length === 0) {
      alert("Title, Description, and at least one Skill tag are required.");
      return;
    }

    setFormLoading(true);
    try {
      const payload = {
        title: title.trim(),
        skills: skillsList.join(", "),
        experience: experience.trim(),
        salary: salary.trim(),
        location: location.trim(),
        description: description.trim()
      };

      if (editingJob) {
        // Edit Action
        await api.put(`/api/job-descriptions/${editingJob.jdId}`, payload);
        alert("Job Description Updated Successfully");
      } else {
        // Create Action
        await api.post("/api/job-descriptions", payload);
        // Default backend creates as 'Pending' (Draft)
        alert("Job Description Saved as Draft");
      }
      setModalOpen(false);
      fetchJobs();
    } catch (err) {
      console.error("Save failed:", err);
      alert(err.response?.data?.message || "Failed to save job posting");
    } finally {
      setFormLoading(false);
    }
  };

  const handlePublishJob = async (id) => {
    if (!id) {
      alert("Invalid Job ID");
      return;
    }
    if (!window.confirm("Publish this job description? Active candidates will immediately be able to view and apply.")) return;
    try {
      console.log(id);
      await api.put(`/api/job-descriptions/publish/${id}`);
      alert("Job Published Successfully");
      fetchJobs();
    } catch (err) {
      alert(err.response?.data?.message || "Publishing failed");
    }
  };

  const handleCloseJob = async (id) => {
    if (!window.confirm("Are you sure you want to close applications for this job opening?")) return;
    try {
      await api.put(`/api/job-descriptions/close/${id}`);
      alert("Job Closed Successfully");
      fetchJobs();
    } catch (err) {
      alert(err.response?.data?.message || "Close operation failed");
    }
  };

  const handleDuplicateJob = async (job) => {
    try {
      const payload = {
        title: `Copy of ${job.title}`,
        skills: job.skills || "",
        experience: job.experience || "",
        salary: job.salary || "",
        location: job.location || "",
        description: job.description || ""
      };
      await api.post("/api/job-descriptions", payload);
      alert("Job Duplicated as Draft Successfully");
      fetchJobs();
    } catch (err) {
      alert("Failed to duplicate job posting");
    }
  };

  const confirmDelete = (job) => {
    setJobToDelete(job);
    setDeleteOpen(true);
  };

  const handleDeleteJob = async () => {
    if (!jobToDelete || !jobToDelete.jdId) return;
    try {
      await api.delete(`/api/job-descriptions/${jobToDelete.jdId}`);
      alert("Job Description Deleted Successfully");
      setDeleteOpen(false);
      setJobToDelete(null);
      fetchJobs();
    } catch (err) {
      alert("Failed to delete job posting");
    }
  };

  // Helper Stats Calculation
  const getJobStats = () => {
    const total = jobs.length;
    const active = jobs.filter(j => j.status === "Open").length;
    const draft = jobs.filter(j => j.status === "Pending" || !j.status).length;
    const closed = jobs.filter(j => j.status === "Closed").length;
    return { total, active, draft, closed };
  };

  const statsObj = getJobStats();

  // Search & Filters Logic
  const getFilteredJobs = () => {
    let result = [...jobs];

    // Search
    if (search.trim()) {
      const query = search.toLowerCase();
      result = result.filter(
        j =>
          j.title?.toLowerCase().includes(query) ||
          j.skills?.toLowerCase().includes(query) ||
          j.location?.toLowerCase().includes(query)
      );
    }

    // Status Filter
    if (filterStatus !== "All") {
      result = result.filter(j => {
        if (filterStatus === "Active") return j.status === "Open";
        if (filterStatus === "Draft") return j.status === "Pending" || !j.status;
        return j.status === filterStatus;
      });
    }

    // Location Filter
    if (filterLocation !== "All") {
      result = result.filter(j => j.location === filterLocation);
    }

    // Sort Logic
    result.sort((a, b) => {
      if (sortBy === "newest") return b.jdId - a.jdId;
      if (sortBy === "oldest") return a.jdId - b.jdId;
      if (sortBy === "title-asc") return a.title?.localeCompare(b.title);
      if (sortBy === "title-desc") return b.title?.localeCompare(a.title);
      return 0;
    });

    return result;
  };

  const filteredJobs = getFilteredJobs();

  // Pagination Logic
  const indexOfLastItem = currentPage * itemsPerPage;
  const indexOfFirstItem = indexOfLastItem - itemsPerPage;
  const currentItems = filteredJobs.slice(indexOfFirstItem, indexOfLastItem);
  const totalPages = Math.ceil(filteredJobs.length / itemsPerPage);

  const handlePageChange = (pageNumber) => {
    setCurrentPage(pageNumber);
  };

  // Status Badge Mapper
  const getStatusBadge = (status) => {
    if (status === "Open") return <Badge variant="success">Active</Badge>;
    if (status === "Closed") return <Badge variant="danger">Closed</Badge>;
    return <Badge variant="secondary">Draft</Badge>;
  };

  const uniqueLocations = ["All", ...new Set(jobs.map(j => j.location).filter(Boolean))];

  return (
    <AppLayout>
      <div className="container-fluid px-0 text-white">

        {/* 1. HEADER */}
        <div className="d-flex flex-column flex-md-row justify-content-between align-items-md-center gap-3 mb-4">
          <div>
            <h2 className="fw-bold mb-1" style={{ fontFamily: "var(--font-sans)", color: "var(--text-primary)" }}>
              Job Postings
            </h2>
            <p className="text-muted mb-0" style={{ fontSize: "0.9rem" }}>
              Create, preview, and coordinate your candidate requisitions.
            </p>
          </div>
          <Button variant="primary" className="d-flex align-items-center gap-2" onClick={openCreateModal}>
            <FaPlus size={14} /> Create New Job
          </Button>
        </div>

        {/* 2. REAL JOB STATISTICS */}
        <div className="row g-4 mb-4">
          <div className="col-6 col-md-3">
            <StatCard title="Total Positions" value={statsObj.total} icon={<FaBriefcase />} loading={loading} description="Positions created" />
          </div>
          <div className="col-6 col-md-3">
            <StatCard title="Active Roles" value={statsObj.active} icon={<FaBriefcase />} loading={loading} description="Open for applications" />
          </div>
          <div className="col-6 col-md-3">
            <StatCard title="Draft Postings" value={statsObj.draft} icon={<FaBriefcase />} loading={loading} description="Work in progress" />
          </div>
          <div className="col-6 col-md-3">
            <StatCard title="Closed Roles" value={statsObj.closed} icon={<FaBriefcase />} loading={loading} description="Closed positions" />
          </div>
        </div>

        {/* 3. MANAGEMENT TOOLBAR */}
        <Card className="surface-custom border-custom mb-4">
          <CardContent className="p-3 d-flex flex-column flex-md-row gap-3 align-items-center justify-content-between">
            {/* Search */}
            <div className="position-relative w-100" style={{ maxWidth: "350px" }}>
              <FaSearch className="position-absolute text-muted" style={{ left: "12px", top: "14px" }} />
              <input
                type="text"
                className="form-control ps-5"
                placeholder="Search job title, skills, location..."
                value={search}
                onChange={(e) => { setSearch(e.target.value); setCurrentPage(1); }}
              />
            </div>

            {/* Filters */}
            <div className="d-flex flex-wrap align-items-center gap-2 w-100 justify-content-md-end">
              <div style={{ minWidth: "130px" }}>
                <Select
                  value={filterStatus}
                  onChange={(e) => { setFilterStatus(e.target.value); setCurrentPage(1); }}
                  options={[
                    { value: "All", label: "All Statuses" },
                    { value: "Active", label: "Active" },
                    { value: "Draft", label: "Draft" },
                    { value: "Closed", label: "Closed" }
                  ]}
                  className="mb-0"
                />
              </div>

              <div style={{ minWidth: "140px" }}>
                <Select
                  value={filterLocation}
                  onChange={(e) => { setFilterLocation(e.target.value); setCurrentPage(1); }}
                  options={uniqueLocations.map(loc => ({ value: loc, label: loc === "All" ? "All Locations" : loc }))}
                  className="mb-0"
                />
              </div>

              <div style={{ minWidth: "130px" }}>
                <Select
                  value={sortBy}
                  onChange={(e) => setSortBy(e.target.value)}
                  options={[
                    { value: "newest", label: "Newest First" },
                    { value: "oldest", label: "Oldest First" },
                    { value: "title-asc", label: "Title A-Z" },
                    { value: "title-desc", label: "Title Z-A" }
                  ]}
                  className="mb-0"
                />
              </div>

              {/* View Toggle */}
              <div className="btn-group border border-secondary border-opacity-10 rounded">
                <button
                  type="button"
                  onClick={() => setViewMode("grid")}
                  className={`btn btn-custom btn-custom-ghost p-2 ${viewMode === "grid" ? "bg-primary text-white" : "text-muted"}`}
                  aria-label="Grid View"
                  style={{ border: "none" }}
                >
                  <FaThLarge size={14} />
                </button>
                <button
                  type="button"
                  onClick={() => setViewMode("table")}
                  className={`btn btn-custom btn-custom-ghost p-2 ${viewMode === "table" ? "bg-primary text-white" : "text-muted"}`}
                  aria-label="Table View"
                  style={{ border: "none" }}
                >
                  <FaList size={14} />
                </button>
              </div>
            </div>
          </CardContent>
        </Card>

        {/* 4. CONTENT VIEW */}
        {loading ? (
          <div className="row g-4">
            <div className="col-md-4"><Skeleton variant="rect" width="100%" height={250} /></div>
            <div className="col-md-4"><Skeleton variant="rect" width="100%" height={250} /></div>
            <div className="col-md-4"><Skeleton variant="rect" width="100%" height={250} /></div>
          </div>
        ) : error ? (
          <ErrorState title="Failed to load open positions" onRetry={fetchJobs} />
        ) : filteredJobs.length === 0 ? (
          <EmptyState title="No Jobs Found" description="Try broadening your search term or select other filters." actionText="Reset Filters" onActionClick={() => { setSearch(""); setFilterStatus("All"); setFilterLocation("All"); }} />
        ) : viewMode === "grid" ? (
          /* GRID VIEW */
          <div className="row g-4">
            {currentItems.map((job, index) => (
              <div className="col-md-6 col-lg-4" key={job.jdId || job.id || `job-fallback-${index}`}>
                <Card className="surface-custom border-custom h-100 d-flex flex-column justify-content-between">
                  <CardContent className="p-4 d-flex flex-column gap-3">
                    <div className="d-flex justify-content-between align-items-start">
                      {getStatusBadge(job.status)}
                      <div className="text-muted" style={{ fontSize: "0.75rem" }}>
                        ID: #{job.jdId}
                      </div>
                    </div>

                    <div>
                      <h4 className="fw-bold mb-1" style={{ color: "var(--text-primary)", fontSize: "1.2rem" }}>
                        {job.title}
                      </h4>
                      <span className="text-muted" style={{ fontSize: "0.85rem" }}>Created by: {job.created_by || "Recruiter"}</span>
                    </div>

                    <div className="d-flex flex-wrap gap-1">
                      {job.skills?.split(",").slice(0, 3).map((s, idx) => (
                        <Badge key={idx} variant="info" style={{ fontSize: "0.7rem", padding: "3px 6px" }}>
                          {s.trim()}
                        </Badge>
                      ))}
                      {job.skills?.split(",").length > 3 && (
                        <span className="text-muted align-self-center" style={{ fontSize: "0.75rem" }}>
                          +{job.skills.split(",").length - 3} more
                        </span>
                      )}
                    </div>

                    <div className="mt-2 d-flex flex-column gap-1.5" style={{ fontSize: "0.85rem", color: "var(--text-secondary)" }}>
                      <div className="d-flex align-items-center gap-2">
                        <FaMapMarkerAlt className="text-primary-light" /> <span>{job.location || "Remote"}</span>
                      </div>
                      <div className="d-flex align-items-center gap-2">
                        <FaMoneyBillWave className="text-primary-light" /> <span>{job.salary || "Not Specified"}</span>
                      </div>
                      <div className="d-flex align-items-center gap-2">
                        <FaBriefcase className="text-primary-light" /> <span>{job.experience || "Not Specified"}</span>
                      </div>
                    </div>
                  </CardContent>

                  <div className="card-custom-footer p-3 bg-dark bg-opacity-25 border-top d-flex gap-2 justify-content-end" style={{ borderColor: "var(--border)" }}>
                    {recruiterRole !== "Hiring Manager" && (
                      <Button variant="ghost" size="sm" title="Hiring Team" onClick={() => setHiringTeamJob(job)}>
                        <FaUsers />
                      </Button>
                    )}
                    <Button variant="ghost" size="sm" title="Duplicate Requisition" onClick={() => handleDuplicateJob(job)}>
                      <FaCopy />
                    </Button>
                    <Button variant="ghost" size="sm" title="Edit Position" onClick={() => openEditModal(job)}>
                      <FaEdit />
                    </Button>

                    {/* Status Triggers */}
                    {(job.status === "Pending" || !job.status) && (
                      <Button variant="outline" size="sm" className="btn-custom-sm" onClick={() => handlePublishJob(job.jdId)}>
                        <FaPlay size={10} className="me-1" /> Publish
                      </Button>
                    )}
                    {job.status === "Open" && (
                      <Button variant="destructive" size="sm" className="btn-custom-sm" onClick={() => handleCloseJob(job.jdId)}>
                        <FaBan size={10} className="me-1" /> Close
                      </Button>
                    )}
                    {job.status === "Closed" && (
                      <Button variant="outline" size="sm" className="btn-custom-sm" onClick={() => handlePublishJob(job.jdId)}>
                        Reopen
                      </Button>
                    )}

                    <Button variant="ghost" size="sm" className="text-danger" title="Delete Permanent" onClick={() => confirmDelete(job)}>
                      <FaTrashAlt />
                    </Button>
                  </div>
                </Card>
              </div>
            ))}
          </div>
        ) : (
          /* TABLE VIEW */
          <Card className="surface-custom border-custom">
            <CardContent className="p-0">
              <div className="table-responsive">
                <table className="table table-hover align-middle mb-0">
                  <thead>
                    <tr>
                      <th>Job Info</th>
                      <th>Location</th>
                      <th>Experience</th>
                      <th>Salary</th>
                      <th>Status</th>
                      <th className="text-end">Actions</th>
                    </tr>
                  </thead>
                  <tbody>
                    {currentItems.map((job, index) => (
                      <tr key={job.jdId || job.id || `job-fallback-${index}`}>
                        <td>
                          <div className="fw-bold text-white">{job.title}</div>
                          <small className="text-muted">By: {job.created_by || "Recruiter"}</small>
                        </td>
                        <td>{job.location || "Remote"}</td>
                        <td>{job.experience}</td>
                        <td>{job.salary}</td>
                        <td>{getStatusBadge(job.status)}</td>
                        <td className="text-end">
                          <div className="d-inline-flex gap-1">
                            {recruiterRole !== "Hiring Manager" && (
                              <Button variant="ghost" size="sm" title="Hiring Team" onClick={() => setHiringTeamJob(job)}>
                                <FaUsers />
                              </Button>
                            )}
                            <Button variant="ghost" size="sm" title="Duplicate" onClick={() => handleDuplicateJob(job)}>
                              <FaCopy />
                            </Button>
                            <Button variant="ghost" size="sm" title="Edit" onClick={() => openEditModal(job)}>
                              <FaEdit />
                            </Button>

                            {(job.status === "Pending" || !job.status) && (
                              <Button variant="outline" size="sm" className="btn-custom-sm py-1 px-2" onClick={() => handlePublishJob(job.jdId)}>
                                Publish
                              </Button>
                            )}
                            {job.status === "Open" && (
                              <Button variant="destructive" size="sm" className="btn-custom-sm py-1 px-2" onClick={() => handleCloseJob(job.jdId)}>
                                Close
                              </Button>
                            )}
                            {job.status === "Closed" && (
                              <Button variant="outline" size="sm" className="btn-custom-sm py-1 px-2" onClick={() => handlePublishJob(job.jdId)}>
                                Reopen
                              </Button>
                            )}

                            <Button variant="ghost" size="sm" className="text-danger" title="Delete" onClick={() => confirmDelete(job)}>
                              <FaTrashAlt />
                            </Button>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </CardContent>
          </Card>
        )}

        {/* 5. PAGINATION PANEL */}
        {!loading && totalPages > 1 && (
          <div className="d-flex justify-content-between align-items-center mt-4">
            <span className="text-muted" style={{ fontSize: "0.85rem" }}>
              Showing {indexOfFirstItem + 1} to {Math.min(indexOfLastItem, filteredJobs.length)} of {filteredJobs.length} postings
            </span>
            <div className="d-flex gap-2">
              <Button
                variant="outline"
                size="sm"
                disabled={currentPage === 1}
                onClick={() => handlePageChange(currentPage - 1)}
              >
                Previous
              </Button>
              {[...Array(totalPages).keys()].map((p) => (
                <Button
                  key={p + 1}
                  variant={currentPage === p + 1 ? "primary" : "outline"}
                  size="sm"
                  onClick={() => handlePageChange(p + 1)}
                >
                  {p + 1}
                </Button>
              ))}
              <Button
                variant="outline"
                size="sm"
                disabled={currentPage === totalPages}
                onClick={() => handlePageChange(currentPage + 1)}
              >
                Next
              </Button>
            </div>
          </div>
        )}

        {/* 6. CREATE / EDIT DIALOG FORM MODAL */}
        {modalOpen && (
          <Modal
            isOpen={modalOpen}
            onClose={() => setModalOpen(false)}
            title={editingJob ? "Edit Job Posting" : "Post a New Requisition"}
            size="lg"
            footer={
              <>
                <Button variant="ghost" onClick={() => setModalOpen(false)}>
                  Cancel
                </Button>
                <Button variant="outline" onClick={() => setPreviewOpen(true)}>
                  <FaEye className="me-1" /> Preview
                </Button>
                <Button variant="primary" loading={formLoading} onClick={() => handleSaveJob()}>
                  Save as Draft
                </Button>
              </>
            }
          >
            <form onSubmit={(e) => { e.preventDefault(); handleSaveJob(); }} className="d-flex flex-column gap-3 text-start">
              <div className="row g-3">
                <div className="col-md-6">
                  <Input
                    id="title"
                    label="Job Title"
                    placeholder="e.g. Senior React Developer"
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    required
                  />
                </div>
                <div className="col-md-6">
                  <Input
                    id="location"
                    label="Location / Mode"
                    placeholder="e.g. New York, NY / Remote"
                    value={location}
                    onChange={(e) => setLocation(e.target.value)}
                  />
                </div>
              </div>

              <div className="row g-3">
                <div className="col-md-6">
                  <Input
                    id="experience"
                    label="Experience Target"
                    placeholder="e.g. 3+ years"
                    value={experience}
                    onChange={(e) => setExperience(e.target.value)}
                  />
                </div>
                <div className="col-md-6">
                  <Input
                    id="salary"
                    label="Salary Bracket"
                    placeholder="e.g. $120,000 - $140,000"
                    value={salary}
                    onChange={(e) => setSalary(e.target.value)}
                  />
                </div>
              </div>

              {/* Skills Tag Management */}
              <div>
                <label className="form-label-custom mb-1">Required Professional Skills</label>
                <div className="input-group">
                  <input
                    type="text"
                    className="form-control"
                    placeholder="Type a skill and press Enter (e.g. JavaScript)"
                    value={skillsInput}
                    onChange={(e) => setSkillsInput(e.target.value)}
                    onKeyDown={handleAddSkill}
                  />
                  <Button type="button" variant="secondary" onClick={handleAddSkill}>
                    Add
                  </Button>
                </div>
                <div className="d-flex flex-wrap gap-1.5 mt-2">
                  {skillsList.map((skill, index) => (
                    <span
                      key={index}
                      className="badge-custom badge-custom-primary d-inline-flex align-items-center gap-1.5"
                      style={{ fontSize: "0.8rem", padding: "5px 10px" }}
                    >
                      {skill}
                      <FaTimes
                        style={{ cursor: "pointer" }}
                        onClick={() => handleRemoveSkill(skill)}
                        size={10}
                      />
                    </span>
                  ))}
                  {skillsList.length === 0 && (
                    <span className="text-muted" style={{ fontSize: "0.8rem" }}>
                      * No skills added. Add at least one.
                    </span>
                  )}
                </div>
              </div>

              <div>
                <label htmlFor="description" className="form-label-custom mb-1">Detailed Description</label>
                <textarea
                  id="description"
                  className="form-control"
                  rows="6"
                  placeholder="Enter detailed job criteria, requirements, and benefits..."
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  required
                />
              </div>
            </form>
          </Modal>
        )}

        {/* 7. PREVIEW MODAL */}
        {previewOpen && (
          <Modal
            isOpen={previewOpen}
            onClose={() => setPreviewOpen(false)}
            title="Job Description Preview"
            size="md"
            footer={
              <Button variant="primary" onClick={() => setPreviewOpen(false)}>
                Back to Editing
              </Button>
            }
          >
            <div className="d-flex flex-column gap-3 text-white text-start">
              <div>
                <h3 className="fw-bold mb-0 text-primary">{title || "Untitled Job"}</h3>
                <small className="text-muted">Target Location: {location || "Remote"}</small>
              </div>
              <hr style={{ borderColor: "var(--border)" }} />

              <div className="row g-2">
                <div className="col-6">
                  <span className="text-muted d-block" style={{ fontSize: "0.8rem" }}>Experience level</span>
                  <strong>{experience || "Not Specified"}</strong>
                </div>
                <div className="col-6">
                  <span className="text-muted d-block" style={{ fontSize: "0.8rem" }}>Estimated Salary</span>
                  <strong>{salary || "Not Specified"}</strong>
                </div>
              </div>

              <div>
                <h6 className="fw-semibold text-secondary-custom mb-1">Skills Stack Required</h6>
                <div className="d-flex flex-wrap gap-1 mt-1">
                  {skillsList.map((skill, i) => (
                    <Badge key={i} variant="info">
                      {skill}
                    </Badge>
                  ))}
                  {skillsList.length === 0 && <span className="text-muted">None specified</span>}
                </div>
              </div>

              <div>
                <h6 className="fw-semibold text-secondary-custom mb-1">Position Description</h6>
                <p className="mb-0 text-muted" style={{ fontSize: "0.9rem", whiteSpace: "pre-wrap", lineHeight: 1.6 }}>
                  {description || "No description provided."}
                </p>
              </div>
            </div>
          </Modal>
        )}

        {/* 8. DELETE CONFIRMATION DIALOG */}
        {deleteOpen && (
          <Modal
            isOpen={deleteOpen}
            onClose={() => setDeleteOpen(false)}
            title="Delete Posting"
            size="sm"
            footer={
              <>
                <Button variant="ghost" onClick={() => setDeleteOpen(false)}>
                  Cancel
                </Button>
                <Button variant="destructive" onClick={handleDeleteJob}>
                  Confirm Delete
                </Button>
              </>
            }
          >
            <p className="text-muted mb-0 text-start" style={{ fontSize: "0.95rem" }}>
              Are you sure you want to permanently delete **{jobToDelete?.title}**? All candidate applications associated with this posting will remain intact but the posting itself will be deleted.
            </p>
          </Modal>
        )}

        {/* 9. HIRING TEAM ASSIGNMENTS MODAL */}
        {hiringTeamJob && (
          <Modal
            isOpen={hiringTeamJob !== null}
            onClose={() => setHiringTeamJob(null)}
            title="Manage Hiring Team"
            size="md"
          >
            <HiringTeamManager jobId={hiringTeamJob.jdId} jobTitle={hiringTeamJob.title} />
          </Modal>
        )}

      </div>
    </AppLayout>
  );
}

export default Jobs;

import { useEffect, useState } from "react";
import api from "../services/api";
import AppLayout from "../components/layout/AppLayout";
import Badge from "../components/ui/Badge";
import { FaFileAlt, FaCheckCircle, FaSearch, FaEye, FaDownload } from "react-icons/fa";

const PIPELINE_STAGES = ["Pending", "Screening", "Shortlisted", "Interview", "Hired"];

function MyApplications() {
    const [applications, setApplications] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState("");
    const [statusFilter, setStatusFilter] = useState("");

    const email = localStorage.getItem("email") || "";

    useEffect(() => {
        const fetchApplications = async () => {
            try {
                const response = await api.get(`/api/applications/email/${email}`);
                setTimeout(() => { setApplications(response.data || []); setLoading(false); }, 0);
            } catch {
                const demoData = [
                    { id: 1, candidate_name: "Candidate User", job_id: 1, resume_file: "demo.pdf", status: "Shortlisted", match_score: 82, created_at: "2026-07-01T10:00:00Z" },
                    { id: 2, candidate_name: "Candidate User", job_id: 2, resume_file: "demo2.pdf", status: "Pending", match_score: null, created_at: "2026-07-05T14:30:00Z" },
                    { id: 3, candidate_name: "Candidate User", job_id: 3, resume_file: "demo3.pdf", status: "Interview", match_score: 91, created_at: "2026-06-28T09:00:00Z" }
                ];
                setTimeout(() => { setApplications(demoData); setLoading(false); }, 0);
            }
        };
        fetchApplications();
    }, [email]);

    const getStatusVariant = (status) => {
        const map = { Pending: "warning", Screening: "info", Shortlisted: "primary", Interview: "info", Hired: "success", Rejected: "danger" };
        return map[status] || "secondary";
    };

    const getStatusColor = (status) => {
        const map = {
            Pending: "#f59e0b", Screening: "#3b82f6", Shortlisted: "#6366f1",
            Interview: "#06b6d4", Hired: "#10b981", Rejected: "#ef4444"
        };
        return map[status] || "#64748b";
    };

    const getStageIndex = (status) => {
        if (status === "Rejected") return -1;
        return PIPELINE_STAGES.indexOf(status);
    };

    const filtered = applications.filter(app => {
        const q = searchQuery.toLowerCase();
        const matchSearch = !q || app.candidate_name?.toLowerCase().includes(q) || String(app.job_id).includes(q);
        const matchStatus = !statusFilter || app.status === statusFilter;
        return matchSearch && matchStatus;
    });

    return (
        <AppLayout>
            <div className="container-fluid px-0">
                {/* Header */}
                <div className="d-flex flex-wrap justify-content-between align-items-center mb-4 gap-2">
                    <div>
                        <h2 className="fw-bold mb-1" style={{ fontFamily: "var(--font-sans)", color: "var(--text-primary)" }}>
                            My Applications
                        </h2>
                        <p className="mb-0" style={{ color: "var(--text-secondary)", fontSize: "0.9rem" }}>
                            {applications.length} total application{applications.length !== 1 ? "s" : ""}
                        </p>
                    </div>
                </div>

                {/* Filters */}
                <div className="card-custom surface-custom border-custom p-3 mb-4" style={{ borderRadius: "var(--radius-md)" }}>
                    <div className="row g-3">
                        <div className="col-md-6">
                            <div className="position-relative">
                                <FaSearch style={{ position: "absolute", left: 12, top: "50%", transform: "translateY(-50%)", color: "var(--text-secondary)", fontSize: "0.85rem" }} />
                                <input
                                    type="text"
                                    className="form-control"
                                    placeholder="Search applications…"
                                    value={searchQuery}
                                    onChange={e => setSearchQuery(e.target.value)}
                                    style={{
                                        background: "var(--background)", color: "var(--text-primary)",
                                        border: "1px solid var(--border)", borderRadius: "var(--radius-sm)",
                                        padding: "10px 14px 10px 36px", fontSize: "0.9rem"
                                    }}
                                />
                            </div>
                        </div>
                        <div className="col-md-3">
                            <select
                                className="form-select"
                                value={statusFilter}
                                onChange={e => setStatusFilter(e.target.value)}
                                style={{
                                    background: "var(--background)", color: "var(--text-primary)",
                                    border: "1px solid var(--border)", borderRadius: "var(--radius-sm)",
                                    padding: "10px 14px", fontSize: "0.9rem"
                                }}
                            >
                                <option value="">All Statuses</option>
                                {[...PIPELINE_STAGES, "Rejected"].map(s => <option key={s} value={s}>{s}</option>)}
                            </select>
                        </div>
                    </div>
                </div>

                {/* Application Cards */}
                {loading ? (
                    <div className="text-center py-5" style={{ color: "var(--text-secondary)" }}>Loading applications…</div>
                ) : filtered.length === 0 ? (
                    <div className="text-center py-5">
                        <FaFileAlt size={48} style={{ color: "var(--text-secondary)", opacity: 0.3, marginBottom: 16 }} />
                        <h5 style={{ color: "var(--text-secondary)" }}>No applications found</h5>
                        <p style={{ fontSize: "0.9rem", color: "var(--text-secondary)" }}>
                            {applications.length === 0 ? "Start applying to open positions!" : "Try adjusting your filters."}
                        </p>
                    </div>
                ) : (
                    <div className="d-flex flex-column gap-3">
                        {filtered.map((app, index) => {
                            const stageIdx = getStageIndex(app.status);
                            const isRejected = app.status === "Rejected";

                            return (
                                <div
                                    key={app.id || `app-fallback-${index}`}
                                    className="card-custom surface-custom border-custom p-4"
                                    style={{
                                        borderRadius: "var(--radius-md)",
                                        borderLeft: `4px solid ${getStatusColor(app.status)}`,
                                        transition: "transform 0.2s ease"
                                    }}
                                    onMouseEnter={e => e.currentTarget.style.transform = "translateX(4px)"}
                                    onMouseLeave={e => e.currentTarget.style.transform = "translateX(0)"}
                                >
                                    {/* Top Row: Info + Badge */}
                                    <div className="d-flex flex-wrap justify-content-between align-items-start mb-3 gap-2">
                                        <div>
                                            <h6 className="fw-bold mb-1" style={{ color: "var(--text-primary)", fontSize: "1rem" }}>
                                                Application #{app.id}
                                            </h6>
                                            <div className="d-flex flex-wrap gap-3" style={{ fontSize: "0.85rem", color: "var(--text-secondary)" }}>
                                                <span>Job ID: #{app.job_id}</span>
                                                {app.match_score && <span>AI Score: <strong style={{ color: app.match_score >= 70 ? "#10b981" : "#f59e0b" }}>{app.match_score}%</strong></span>}
                                                {app.created_at && <span>Applied: {new Date(app.created_at).toLocaleDateString()}</span>}
                                            </div>
                                        </div>
                                        <div className="d-flex align-items-center gap-2">
                                            <Badge variant={getStatusVariant(app.status)}>{app.status}</Badge>
                                            {app.resume_file && (
                                                <a
                                                    href={`${api.defaults.baseURL}/uploads/resumes/${app.resume_file}`}
                                                    target="_blank"
                                                    rel="noreferrer"
                                                    className="btn-custom btn-custom-ghost p-1"
                                                    style={{ border: "none", background: "transparent", color: "var(--primary)", fontSize: "0.9rem" }}
                                                    title="View Resume"
                                                >
                                                    <FaEye />
                                                </a>
                                            )}
                                        </div>
                                    </div>

                                    {/* Pipeline Timeline */}
                                    <div className="d-flex align-items-center gap-0" style={{ overflowX: "auto", paddingBottom: 4 }}>
                                        {PIPELINE_STAGES.map((stage, i) => {
                                            const isCompleted = !isRejected && i <= stageIdx;
                                            const isCurrent = !isRejected && i === stageIdx;
                                            const dotColor = isCompleted ? getStatusColor(stage) : "var(--border)";

                                            return (
                                                <div key={stage} className="d-flex align-items-center" style={{ flexShrink: 0 }}>
                                                    <div className="d-flex flex-column align-items-center" style={{ minWidth: 70 }}>
                                                        <div style={{
                                                            width: isCurrent ? 30 : 22, height: isCurrent ? 30 : 22,
                                                            borderRadius: "50%",
                                                            background: isCompleted ? dotColor : "transparent",
                                                            border: isCompleted ? "none" : `2px solid var(--border)`,
                                                            display: "flex", alignItems: "center", justifyContent: "center",
                                                            transition: "all 0.3s ease",
                                                            boxShadow: isCurrent ? `0 0 0 4px ${dotColor}33` : "none"
                                                        }}>
                                                            {isCompleted && <FaCheckCircle style={{ color: "#fff", fontSize: isCurrent ? "0.75rem" : "0.6rem" }} />}
                                                        </div>
                                                        <span style={{
                                                            fontSize: "0.65rem", marginTop: 4,
                                                            color: isCompleted ? "var(--text-primary)" : "var(--text-secondary)",
                                                            fontWeight: isCurrent ? 700 : 400
                                                        }}>
                                                            {stage}
                                                        </span>
                                                    </div>
                                                    {i < PIPELINE_STAGES.length - 1 && (
                                                        <div style={{
                                                            width: 30, height: 2,
                                                            background: (!isRejected && i < stageIdx) ? getStatusColor(PIPELINE_STAGES[i + 1]) : "var(--border)",
                                                            marginBottom: 16
                                                        }} />
                                                    )}
                                                </div>
                                            );
                                        })}
                                        {isRejected && (
                                            <div className="d-flex flex-column align-items-center ms-3" style={{ minWidth: 70 }}>
                                                <div style={{
                                                    width: 30, height: 30, borderRadius: "50%",
                                                    background: "#ef4444",
                                                    display: "flex", alignItems: "center", justifyContent: "center",
                                                    boxShadow: "0 0 0 4px rgba(239,68,68,0.2)"
                                                }}>
                                                    <span style={{ color: "#fff", fontWeight: 700, fontSize: "0.8rem" }}>✕</span>
                                                </div>
                                                <span style={{ fontSize: "0.65rem", marginTop: 4, color: "#ef4444", fontWeight: 700 }}>
                                                    Rejected
                                                </span>
                                            </div>
                                        )}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </AppLayout>
    );
}

export default MyApplications;

