import { useEffect, useState, useMemo } from "react";
import api from "../services/api";
import AppLayout from "../components/layout/AppLayout";
import Badge from "../components/ui/Badge";
import Button from "../components/ui/Button";
import { FaBell, FaCheck, FaCheckDouble, FaFilter, FaTrash, FaExclamationTriangle, FaInfoCircle, FaCalendarAlt } from "react-icons/fa";

function Notifications() {
    const [notifications, setNotifications] = useState([]);
    const [loading, setLoading] = useState(true);
    const [filterType, setFilterType] = useState("all"); // all, unread, read
    const [categoryFilter, setCategoryFilter] = useState("");

    const fetchNotifications = async () => {
        try {
            const res = await api.get("/api/notifications");
            setNotifications(res.data || []);
        } catch {
            // Demo notifications
            setNotifications([
                { id: 1, type: "INTERVIEW_SCHEDULED", priority: "HIGH", title: "New Interview Scheduled", message: "Technical Interview for John Smith with Sarah Wilson on 2026-07-10", is_read: false, created_at: new Date(Date.now() - 3600000).toISOString() },
                { id: 2, type: "PIPELINE_STAGE_CHANGED", priority: "NORMAL", title: "Pipeline Stage Transition", message: "Candidate Jane Doe moved from Screening to Shortlisted", is_read: false, created_at: new Date(Date.now() - 7200000).toISOString() },
                { id: 3, type: "CANDIDATE_REJECTED", priority: "NORMAL", title: "Candidate Rejected", message: "Candidate Mike Johnson marked Rejected. Reason: Insufficient experience", is_read: true, created_at: new Date(Date.now() - 86400000).toISOString() },
                { id: 4, type: "FEEDBACK_SUBMITTED", priority: "NORMAL", title: "Feedback Evaluation Logged", message: "Scorecard evaluation logged for Emily Brown (Rating: 4/5)", is_read: true, created_at: new Date(Date.now() - 172800000).toISOString() },
                { id: 5, type: "INTERVIEW_RESCHEDULED", priority: "HIGH", title: "Interview Booking Updated", message: "Interview status updated to Rescheduled for candidate Alex Wilson", is_read: false, created_at: new Date(Date.now() - 5400000).toISOString() }
            ]);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchNotifications();
    }, []);

    const markAsRead = async (id) => {
        try { await api.put(`/api/notifications/read/${id}`); } catch { /* OK */ }
        setNotifications(prev => prev.map(n => n.id === id ? { ...n, is_read: true } : n));
    };

    const markAllRead = async () => {
        try { await api.put("/api/notifications/read-all"); } catch { /* OK */ }
        setNotifications(prev => prev.map(n => ({ ...n, is_read: true })));
    };

    const categories = useMemo(() => [...new Set(notifications.map(n => n.type))], [notifications]);
    const unreadCount = notifications.filter(n => !n.is_read).length;

    const filtered = useMemo(() => {
        return notifications.filter(n => {
            if (filterType === "unread" && n.is_read) return false;
            if (filterType === "read" && !n.is_read) return false;
            if (categoryFilter && n.type !== categoryFilter) return false;
            return true;
        });
    }, [notifications, filterType, categoryFilter]);

    const getTimeAgo = (dateStr) => {
        if (!dateStr) return "";
        const diff = Date.now() - new Date(dateStr).getTime();
        const mins = Math.floor(diff / 60000);
        if (mins < 1) return "Just now";
        if (mins < 60) return `${mins}m ago`;
        const hrs = Math.floor(mins / 60);
        if (hrs < 24) return `${hrs}h ago`;
        const days = Math.floor(hrs / 24);
        return `${days}d ago`;
    };

    const getTypeIcon = (type) => {
        const map = {
            INTERVIEW_SCHEDULED: <FaCalendarAlt />,
            INTERVIEW_RESCHEDULED: <FaCalendarAlt />,
            PIPELINE_STAGE_CHANGED: <FaInfoCircle />,
            CANDIDATE_REJECTED: <FaExclamationTriangle />,
            FEEDBACK_SUBMITTED: <FaCheck />
        };
        return map[type] || <FaBell />;
    };

    const getTypeColor = (type) => {
        const map = {
            INTERVIEW_SCHEDULED: "#06b6d4",
            INTERVIEW_RESCHEDULED: "#f59e0b",
            PIPELINE_STAGE_CHANGED: "#6366f1",
            CANDIDATE_REJECTED: "#ef4444",
            FEEDBACK_SUBMITTED: "#10b981"
        };
        return map[type] || "var(--primary)";
    };

    const formatCategory = (type) => {
        return type.replace(/_/g, " ").replace(/\b\w/g, c => c.toUpperCase()).toLowerCase().replace(/^\w/, c => c.toUpperCase());
    };

    return (
        <AppLayout>
            <div className="container-fluid px-0">
                {/* Header */}
                <div className="d-flex flex-wrap justify-content-between align-items-center mb-4 gap-2">
                    <div>
                        <h2 className="fw-bold mb-1" style={{ fontFamily: "var(--font-sans)", color: "var(--text-primary)" }}>
                            <FaBell className="me-2" style={{ color: "var(--primary)" }} />
                            Notification Center
                        </h2>
                        <p className="mb-0" style={{ color: "var(--text-secondary)", fontSize: "0.9rem" }}>
                            {unreadCount} unread · {notifications.length} total
                        </p>
                    </div>
                    <div className="d-flex gap-2">
                        {unreadCount > 0 && (
                            <Button variant="outline" onClick={markAllRead}>
                                <FaCheckDouble className="me-1" /> Mark All Read
                            </Button>
                        )}
                    </div>
                </div>

                {/* Filters */}
                <div className="card-custom surface-custom border-custom p-3 mb-4" style={{ borderRadius: "var(--radius-md)" }}>
                    <div className="d-flex flex-wrap gap-3 align-items-center">
                        <div className="d-flex gap-1">
                            {[
                                { key: "all", label: "All" },
                                { key: "unread", label: `Unread (${unreadCount})` },
                                { key: "read", label: "Read" }
                            ].map(tab => (
                                <button
                                    key={tab.key}
                                    onClick={() => setFilterType(tab.key)}
                                    style={{
                                        border: "none",
                                        background: filterType === tab.key ? "var(--primary)" : "transparent",
                                        color: filterType === tab.key ? "#fff" : "var(--text-secondary)",
                                        padding: "6px 14px",
                                        borderRadius: "var(--radius-sm)",
                                        fontSize: "0.82rem",
                                        fontWeight: 600,
                                        cursor: "pointer",
                                        transition: "all 0.15s ease"
                                    }}
                                >
                                    {tab.label}
                                </button>
                            ))}
                        </div>
                        <select
                            value={categoryFilter}
                            onChange={e => setCategoryFilter(e.target.value)}
                            style={{
                                background: "var(--background)", color: "var(--text-primary)",
                                border: "1px solid var(--border)", borderRadius: "var(--radius-sm)",
                                padding: "6px 12px", fontSize: "0.85rem"
                            }}
                        >
                            <option value="">All Categories</option>
                            {categories.map(cat => (
                                <option key={cat} value={cat}>{formatCategory(cat)}</option>
                            ))}
                        </select>
                    </div>
                </div>

                {/* Notification List */}
                {loading ? (
                    <div className="text-center py-5" style={{ color: "var(--text-secondary)" }}>Loading notifications…</div>
                ) : filtered.length === 0 ? (
                    <div className="text-center py-5">
                        <FaBell size={48} style={{ color: "var(--text-secondary)", opacity: 0.3, marginBottom: 16 }} />
                        <h5 style={{ color: "var(--text-secondary)" }}>No notifications</h5>
                        <p style={{ color: "var(--text-secondary)", fontSize: "0.9rem" }}>
                            {filterType === "unread" ? "All caught up! No unread notifications." : "Notifications will appear here as recruitment events occur."}
                        </p>
                    </div>
                ) : (
                    <div className="d-flex flex-column gap-2">
                        {filtered.map(notif => (
                            <div
                                key={notif.id}
                                className="card-custom surface-custom border-custom p-3 d-flex align-items-start gap-3"
                                style={{
                                    borderRadius: "var(--radius-sm)",
                                    borderLeft: `4px solid ${getTypeColor(notif.type)}`,
                                    background: notif.is_read ? "var(--surface)" : "var(--primary-bg, rgba(99,102,241,0.04))",
                                    transition: "transform 0.15s ease"
                                }}
                                onMouseEnter={e => e.currentTarget.style.transform = "translateX(3px)"}
                                onMouseLeave={e => e.currentTarget.style.transform = "translateX(0)"}
                            >
                                {/* Type Icon */}
                                <div style={{
                                    width: 40, height: 40, borderRadius: "50%", flexShrink: 0,
                                    background: getTypeColor(notif.type) + "18",
                                    color: getTypeColor(notif.type),
                                    display: "flex", alignItems: "center", justifyContent: "center",
                                    fontSize: "0.95rem"
                                }}>
                                    {getTypeIcon(notif.type)}
                                </div>

                                {/* Content */}
                                <div style={{ flex: 1, minWidth: 0 }}>
                                    <div className="d-flex justify-content-between align-items-start gap-2 mb-1">
                                        <div className="fw-semibold" style={{ fontSize: "0.9rem", color: "var(--text-primary)" }}>
                                            {notif.title}
                                        </div>
                                        <div className="d-flex align-items-center gap-2 flex-shrink-0">
                                            {notif.priority === "HIGH" && <Badge variant="danger">High</Badge>}
                                            <span style={{ fontSize: "0.72rem", color: "var(--text-secondary)", whiteSpace: "nowrap" }}>
                                                {getTimeAgo(notif.created_at)}
                                            </span>
                                        </div>
                                    </div>
                                    <p className="mb-1" style={{ fontSize: "0.84rem", color: "var(--text-secondary)", lineHeight: 1.4 }}>
                                        {notif.message}
                                    </p>
                                    <div className="d-flex align-items-center gap-2">
                                        <Badge variant="info">{formatCategory(notif.type)}</Badge>
                                        {!notif.is_read && (
                                            <button
                                                onClick={() => markAsRead(notif.id)}
                                                style={{
                                                    border: "none", background: "transparent", color: "var(--primary)",
                                                    fontSize: "0.75rem", cursor: "pointer", padding: "2px 6px"
                                                }}
                                            >
                                                <FaCheck className="me-1" /> Mark read
                                            </button>
                                        )}
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </AppLayout>
    );
}

export default Notifications;

import React, { useState } from "react";
import api from "../services/api";
import { useNavigate } from "react-router-dom";
import Button from "../components/ui/Button";
import Input from "../components/ui/Input";
import Select from "../components/ui/Select";
import { Card, CardContent } from "../components/ui/Card";
import { FaUserCircle, FaRobot } from "react-icons/fa";

function Register() {
  const navigate = useNavigate();

  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("Candidate");
  const [loading, setLoading] = useState(false);
  const [wakingUp, setWakingUp] = useState(false);
  const [showPassword, setShowPassword] = useState(false);

  const handleRegister = async (e) => {
    if (e) e.preventDefault();

    if (!name.trim() || !email.trim() || !password || !role) {
      alert("All fields are required");
      return;
    }

    if (password.length < 6) {
      alert("Password must be at least 6 characters long");
      return;
    }

    setLoading(true);
    setWakingUp(false);

    const wakingUpTimer = setTimeout(() => {
      setWakingUp(true);
    }, 5000);

    try {
      const response = await api.post("/api/auth/register", {
        name: name.trim(),
        email: email.trim().toLowerCase(),
        password,
        role,
      }, { timeout: 60000 });

      alert(response.data.message || "Registration Successful!");
      navigate("/login");
    } catch (error) {
      if (error.code === 'ECONNABORTED' || !error.response) {
        alert("Waking up server, this can take up to a minute on first request. Please try again shortly.");
      } else if (error.response && error.response.data) {
        alert(error.response.data.message || "Registration Failed");
      } else {
        alert("Server Error");
      }
    } finally {
      clearTimeout(wakingUpTimer);
      setWakingUp(false);
      setLoading(false);
    }
  };

  const roleOptions = [
    { value: "Candidate", label: "Candidate (Apply & Track Jobs)" },
    { value: "HR", label: "HR Recruiter (Manage Jobs & Screen Resumes)" },
    { value: "Admin", label: "Admin User (Manage Platform Settings)" }
  ];

  return (
    <div
      className="container-fluid"
      style={{
        minHeight: "100vh",
        background: "linear-gradient(135deg, #0f172a, #1e293b, #2563eb)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: "24px",
      }}
    >
      <Card
        style={{
          width: "100%",
          maxWidth: "500px",
          background: "rgba(255, 255, 255, 0.1)",
          backdropFilter: "blur(16px)",
          border: "1px solid rgba(255, 255, 255, 0.15)",
          borderRadius: "var(--radius-lg)",
        }}
        data-aos="zoom-in"
      >
        <CardContent className="p-4 p-md-5 text-white">
          <div className="text-center mb-4">
            <FaUserCircle size={56} className="text-info mb-2" />
            <h2 className="fw-bold mb-1" style={{ fontFamily: "var(--font-sans)" }}>
              Create Account
            </h2>
            <p className="text-light opacity-75 mb-0" style={{ fontSize: "0.9rem" }}>
              Join the intelligent AI hiring network
            </p>
          </div>

          <form onSubmit={handleRegister}>
            <Input
              id="name"
              type="text"
              label="Full Name"
              placeholder="Alex Morgan"
              value={name}
              onChange={(e) => setName(e.target.value)}
              required
              disabled={loading}
              style={{
                background: "rgba(255,255,255,0.08)",
                border: "1px solid rgba(255,255,255,0.15)",
                color: "#fff",
              }}
            />

            <Input
              id="email"
              type="email"
              label="Email Address"
              placeholder="alex@company.com"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
              disabled={loading}
              style={{
                background: "rgba(255,255,255,0.08)",
                border: "1px solid rgba(255,255,255,0.15)",
                color: "#fff",
              }}
            />

            <div className="position-relative">
              <Input
                id="password"
                type={showPassword ? "text" : "password"}
                label="Password"
                placeholder="••••••••"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
                disabled={loading}
                helperText="Must be at least 6 characters long"
                style={{
                  background: "rgba(255,255,255,0.08)",
                  border: "1px solid rgba(255,255,255,0.15)",
                  color: "#fff",
                  paddingRight: "45px",
                }}
              />
              <button
                type="button"
                className="btn-custom btn-custom-ghost p-1 position-absolute text-light"
                style={{
                  right: "10px",
                  top: "38px",
                  border: "none",
                  background: "transparent",
                  fontSize: "0.85rem",
                  color: "rgba(255,255,255,0.6)",
                }}
                onClick={() => setShowPassword(!showPassword)}
              >
                {showPassword ? "Hide" : "Show"}
              </button>
            </div>

            <Select
              id="role"
              label="Select Platform Role"
              options={roleOptions}
              value={role}
              onChange={(e) => setRole(e.target.value)}
              required
              disabled={loading}
              style={{
                background: "rgba(255,255,255,0.08)",
                border: "1px solid rgba(255,255,255,0.15)",
                color: "#fff",
              }}
            />

            <Button
              type="submit"
              variant="primary"
              className="w-100 mt-4"
              loading={loading}
            >
              Sign Up
            </Button>

            {wakingUp && (
              <div className="alert alert-info py-2 px-3 mt-3 mb-0 text-center" style={{ fontSize: "0.85rem", background: "rgba(13, 202, 240, 0.15)", border: "1px solid rgba(13, 202, 240, 0.3)", color: "#0dcaf0" }}>
                Waking up server, this can take up to a minute on first request
              </div>
            )}

            <Button
              type="button"
              variant="ghost"
              className="w-100 mt-3 text-light text-decoration-none"
              style={{ color: "rgba(255,255,255,0.75)" }}
              onClick={() => navigate("/login")}
              disabled={loading}
            >
              Already have an account? Sign In
            </Button>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}

export default Register;

import React, { useEffect, useState, useCallback } from "react";
import api from "../services/api";
import AppLayout from "../components/layout/AppLayout";
import Button from "../components/ui/Button";
import Badge from "../components/ui/Badge";
import Skeleton from "../components/ui/Skeleton";
import Input from "../components/ui/Input";
import Select from "../components/ui/Select";
import Modal from "../components/ui/Modal";
import { Card, CardContent } from "../components/ui/Card";
import StatCard from "../components/ui/StatCard";
import { 
  FaCog, FaUser, FaLock, FaUsers, FaPlus, FaTrash, FaCheck, FaExclamationTriangle,
  FaPalette, FaBell, FaShieldAlt, FaBuilding, FaServer, FaBrain, FaHistory, FaLink,
  FaEnvelope, FaCalendarAlt, FaCheckCircle, FaExchangeAlt, FaChevronLeft, FaChevronRight, FaEye
} from "react-icons/fa";

function Settings() {
  const userRole = localStorage.getItem("role") || "Recruiter";
  const userEmail = localStorage.getItem("email") || "";
  const isAdmin = userRole === "Admin";

  const [activeTab, setActiveTab] = useState("profile");
  const [profile, setProfile] = useState(null);
  const [organization, setOrganization] = useState(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");
  const [successMessage, setSuccessMessage] = useState("");

  // Personal Profile inputs
  const [nameInput, setNameInput] = useState("");
  const [phoneInput, setPhoneInput] = useState("");
  const [jobTitleInput, setJobTitleInput] = useState("");
  const [timezoneInput, setTimezoneInput] = useState("UTC");
  const [localeInput, setLocaleInput] = useState("en-US");

  // Preferences inputs
  const [themeInput, setThemeInput] = useState("light");
  const [landingPageInput, setLandingPageInput] = useState("/dashboard");
  const [analyticsRangeInput, setAnalyticsRangeInput] = useState("30_days");
  const [candidateViewInput, setCandidateViewInput] = useState("list");
  const [pipelineViewInput, setPipelineViewInput] = useState("kanban");

  // Notification local preferences (persisted locally)
  const [emailAlerts, setEmailAlerts] = useState(true);
  const [bellAlerts, setBellAlerts] = useState(true);
  const [highPriorityAlertsOnly, setHighPriorityAlertsOnly] = useState(false);

  // Security (password change) inputs
  const [currentPassword, setCurrentPassword] = useState("");
  const [newPassword, setNewPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");

  // Organization settings inputs
  const [orgName, setOrgName] = useState("");
  const [orgSlug, setOrgSlug] = useState("");
  const [orgLogo, setOrgLogo] = useState("");
  const [orgIndustry, setOrgIndustry] = useState("");
  const [orgSize, setOrgSize] = useState("");
  const [orgWebsite, setOrgWebsite] = useState("");
  const [orgTimezone, setOrgTimezone] = useState("UTC");
  const [orgLocale, setOrgLocale] = useState("en-US");

  // Recruitment Defaults inputs
  const [defaultPipeline, setDefaultPipeline] = useState("Standard");
  const [defaultInterviewDuration, setDefaultInterviewDuration] = useState(30);
  const [defaultInterviewType, setDefaultInterviewType] = useState("Video");
  const [defaultApplicationStage, setDefaultApplicationStage] = useState("Applied");
  const [defaultAnalyticsRange, setDefaultAnalyticsRange] = useState("30_days");

  // Audit Logs state
  const [auditLogs, setAuditLogs] = useState([]);
  const [auditPage, setAuditPage] = useState(1);
  const [auditTotalPages, setAuditTotalPages] = useState(1);
  const [auditTotalLogs, setAuditTotalLogs] = useState(0);
  const [auditSearch, setAuditSearch] = useState("");
  const [auditCategory, setAuditCategory] = useState("All");
  const [auditResult, setAuditResult] = useState("All");
  const [auditStartDate, setAuditStartDate] = useState("");
  const [auditEndDate, setAuditEndDate] = useState("");
  const [selectedAuditLog, setSelectedAuditLog] = useState(null);
  const [auditModalOpen, setAuditModalOpen] = useState(false);
  const [auditLoading, setAuditLoading] = useState(false);

  // System Diagnostics state
  const [systemInfo, setSystemInfo] = useState(null);
  const [sysInfoLoading, setSysInfoLoading] = useState(false);

  // Unsaved changes warning trigger
  const [isDirty, setIsDirty] = useState(false);

  const fetchSettingsData = useCallback(async () => {
    setLoading(true);
    setError("");
    try {
      // Fetch user profile and preferences
      const profileRes = await api.get("/api/settings/profile");
      const profileData = profileRes.data || {};
      setProfile(profileData);
      setNameInput(profileData.name || "");
      setPhoneInput(profileData.phone || "");
      setJobTitleInput(profileData.job_title || "");
      setTimezoneInput(profileData.timezone || "UTC");
      setLocaleInput(profileData.locale || "en-US");

      setThemeInput(profileData.theme || "light");
      setLandingPageInput(profileData.default_landing_page || "/dashboard");
      setAnalyticsRangeInput(profileData.default_analytics_range || "30_days");
      setCandidateViewInput(profileData.default_candidate_view || "list");
      setPipelineViewInput(profileData.default_pipeline_view || "kanban");

      // Load local notification settings from localStorage
      const savedEmailAlerts = localStorage.getItem("notif_email_alerts") !== "false";
      const savedBellAlerts = localStorage.getItem("notif_bell_alerts") !== "false";
      const savedHighPriorityOnly = localStorage.getItem("notif_high_priority_only") === "true";
      setEmailAlerts(savedEmailAlerts);
      setBellAlerts(savedBellAlerts);
      setHighPriorityAlertsOnly(savedHighPriorityOnly);

      // Fetch organization settings
      if (userRole !== "Candidate" && profileData.organization_id) {
        const orgRes = await api.get("/api/settings/organization");
        const orgData = orgRes.data || {};
        setOrganization(orgData);
        setOrgName(orgData.name || "");
        setOrgSlug(orgData.slug || "");
        setOrgLogo(orgData.logo_url || "");
        setOrgIndustry(orgData.industry || "");
        setOrgSize(orgData.company_size || "");
        setOrgWebsite(orgData.website || "");
        setOrgTimezone(orgData.timezone || "UTC");
        setOrgLocale(orgData.locale || "en-US");

        // Defaults
        setDefaultPipeline(orgData.default_pipeline || "Standard");
        setDefaultInterviewDuration(orgData.default_interview_duration || 30);
        setDefaultInterviewType(orgData.default_interview_type || "Video");
        setDefaultApplicationStage(orgData.default_application_stage || "Applied");
        setDefaultAnalyticsRange(orgData.default_analytics_range || "30_days");
      }
      setIsDirty(false);
    } catch (err) {
      console.error(err);
      setError("Failed to load settings from server. Please refresh.");
    } finally {
      setLoading(false);
    }
  }, [userRole]);

  useEffect(() => {
    fetchSettingsData();
  }, [fetchSettingsData]);

  // Handle Tab Switch
  const handleTabChange = (tab) => {
    if (isDirty) {
      const confirmLeave = window.confirm("You have unsaved changes. Are you sure you want to discard them?");
      if (!confirmLeave) return;
    }
    setActiveTab(tab);
    setSuccessMessage("");
    setError("");
    setIsDirty(false);

    if (tab === "audit" && isAdmin) {
      fetchAuditLogs(1);
    } else if (tab === "sysinfo" && isAdmin) {
      fetchSystemDiagnostics();
    }
  };

  // Fetch Audit Logs
  const fetchAuditLogs = async (pageNo = 1) => {
    setAuditLoading(true);
    try {
      const params = {
        page: pageNo,
        limit: 10,
        search: auditSearch,
        category: auditCategory,
        result: auditResult,
        startDate: auditStartDate,
        endDate: auditEndDate
      };
      const res = await api.get("/api/settings/audit-logs", { params });
      setAuditLogs(res.data.logs || []);
      setAuditPage(res.data.pagination.page);
      setAuditTotalPages(res.data.pagination.pages);
      setAuditTotalLogs(res.data.pagination.total);
    } catch (err) {
      console.error("Failed to query audit logs:", err);
    } finally {
      setAuditLoading(false);
    }
  };

  // Fetch System Diagnostics
  const fetchSystemDiagnostics = async () => {
    setSysInfoLoading(true);
    try {
      const res = await api.get("/api/settings/system-info");
      setSystemInfo(res.data);
    } catch (err) {
      console.error("Failed to ping system status:", err);
    } finally {
      setSysInfoLoading(false);
    }
  };

  const handleUpdateProfile = async (e) => {
    if (e) e.preventDefault();
    if (!nameInput.trim()) return setError("Full Name is required");
    setSaving(true);
    setError("");
    setSuccessMessage("");
    try {
      await api.put("/api/settings/profile", {
        name: nameInput.trim(),
        phone: phoneInput.trim(),
        job_title: jobTitleInput.trim(),
        timezone: timezoneInput,
        locale: localeInput,
        default_landing_page: landingPageInput,
        default_analytics_range: analyticsRangeInput,
        default_candidate_view: candidateViewInput,
        default_pipeline_view: pipelineViewInput,
        theme: themeInput
      });

      // Update document classes instantly for local changes
      document.documentElement.setAttribute("data-theme", themeInput);
      localStorage.setItem("theme", themeInput);

      setSuccessMessage("Personal profile and preferences updated successfully!");
      setIsDirty(false);
      fetchSettingsData();
    } catch (err) {
      setError(err.response?.data?.message || "Failed to update profile settings.");
    } finally {
      setSaving(false);
    }
  };

  const handleUpdateOrganization = async (e) => {
    if (e) e.preventDefault();
    if (!orgName.trim()) return setError("Organization Name is required");
    if (!orgSlug.trim()) return setError("Workspace Slug is required");
    setSaving(true);
    setError("");
    setSuccessMessage("");
    try {
      await api.put("/api/settings/organization", {
        name: orgName.trim(),
        slug: orgSlug.trim(),
        logo_url: orgLogo.trim(),
        industry: orgIndustry.trim(),
        company_size: orgSize,
        website: orgWebsite.trim(),
        timezone: orgTimezone,
        locale: orgLocale,
        default_pipeline: defaultPipeline,
        default_interview_duration: parseInt(defaultInterviewDuration) || 30,
        default_interview_type: defaultInterviewType,
        default_application_stage: defaultApplicationStage,
        default_analytics_range: defaultAnalyticsRange
      });
      setSuccessMessage("Organization settings and default configurations saved!");
      setIsDirty(false);
      fetchSettingsData();
    } catch (err) {
      setError(err.response?.data?.message || "Failed to update organization settings.");
    } finally {
      setSaving(false);
    }
  };

  const handleSaveNotifications = (e) => {
    e.preventDefault();
    localStorage.setItem("notif_email_alerts", emailAlerts);
    localStorage.setItem("notif_bell_alerts", bellAlerts);
    localStorage.setItem("notif_high_priority_only", highPriorityAlertsOnly);
    setSuccessMessage("Notification channel preferences updated locally!");
    setIsDirty(false);
  };

  const handleChangePassword = async (e) => {
    e.preventDefault();
    if (!currentPassword || !newPassword) return setError("Both current and new password are required");
    if (newPassword.length < 6) return setError("New password must be at least 6 characters");
    if (newPassword !== confirmPassword) return setError("Passwords do not match");

    setSaving(true);
    setError("");
    setSuccessMessage("");
    try {
      await api.put("/api/settings/change-password", { currentPassword, newPassword });
      setSuccessMessage("Your credentials have been updated successfully!");
      setCurrentPassword("");
      setNewPassword("");
      setConfirmPassword("");
      setIsDirty(false);
    } catch (err) {
      setError(err.response?.data?.message || "Failed to modify password.");
    } finally {
      setSaving(false);
    }
  };

  const openAuditDetails = (log) => {
    setSelectedAuditLog(log);
    setAuditModalOpen(true);
  };

  const inputStyle = {
    background: "var(--surface-secondary, #f1f5f9)", 
    color: "var(--text-primary)",
    border: "1px solid var(--border)", 
    borderRadius: "var(--radius-sm)",
    padding: "10px 14px", 
    fontSize: "0.9rem", 
    width: "100%"
  };

  const tabs = [
    { key: "profile", label: "Profile", icon: <FaUser />, roles: ["Admin", "HR", "Recruiter", "Hiring Manager", "Interviewer", "Candidate"] },
    { key: "account", label: "Account Status", icon: <FaShieldAlt />, roles: ["Admin", "HR", "Recruiter", "Hiring Manager", "Interviewer", "Candidate"] },
    { key: "preferences", label: "Preferences", icon: <FaPalette />, roles: ["Admin", "HR", "Recruiter", "Hiring Manager", "Interviewer", "Candidate"] },
    { key: "notifications", label: "Notifications", icon: <FaBell />, roles: ["Admin", "HR", "Recruiter", "Hiring Manager", "Interviewer", "Candidate"] },
    { key: "security", label: "Security", icon: <FaLock />, roles: ["Admin", "HR", "Recruiter", "Hiring Manager", "Interviewer", "Candidate"] },
    { key: "organization", label: "Organization", icon: <FaBuilding />, roles: ["Admin"] },
    { key: "defaults", label: "Recruitment Defaults", icon: <FaCog />, roles: ["Admin"] },
    { key: "status", label: "AI & Comms Status", icon: <FaBrain />, roles: ["Admin"] },
    { key: "team", label: "Team & Invites", icon: <FaUsers />, roles: ["Admin", "HR", "Recruiter"] },
    { key: "audit", label: "Audit Logs Explorer", icon: <FaHistory />, roles: ["Admin"] },
    { key: "sysinfo", label: "System Diagnostic", icon: <FaServer />, roles: ["Admin"] }
  ].filter(t => t.roles.includes(userRole));

  return (
    <AppLayout>
      <div className="container-fluid px-0 text-white text-start">

        {/* PAGE TITLE */}
