                  )}

                </>
              )}

            </div>
          </div>

        </div>

      </div>

      {/* AUDIT LOG DETAILS MODAL */}
      <Modal isOpen={auditModalOpen} onClose={() => setAuditModalOpen(false)} title="Audit Event Trace Inspector">
        {selectedAuditLog && (
