              <hr className="my-2 border-secondary" />
              <div><strong>Target Resource Type:</strong> {selectedAuditLog.resource_type}</div>
              <div><strong>Target Resource ID:</strong> {selectedAuditLog.resource_id || "N/A"}</div>

