import React, { useEffect, useState } from "react";
import api from "../services/api";
import AppLayout from "../components/layout/AppLayout";
import Button from "../components/ui/Button";
import Badge from "../components/ui/Badge";
import Input from "../components/ui/Input";
import Select from "../components/ui/Select";
import Modal from "../components/ui/Modal";
import Skeleton from "../components/ui/Skeleton";
import { Card, CardContent } from "../components/ui/Card";
import StatCard from "../components/ui/StatCard";
import { 
  FaUsers, 
  FaUserPlus, 
  FaSearch, 
  FaUserShield, 
  FaClock, 
  FaInfoCircle, 
  FaUndo, 
  FaBan, 
  FaTrash,
  FaEnvelope, 
  FaCrown,
  FaCheckCircle,
  FaUserCog
} from "react-icons/fa";

function Team() {
  const currentUserRole = localStorage.getItem("role") || "HR";
  const currentUserEmail = localStorage.getItem("email") || "";
  const isAdmin = currentUserRole === "Admin";

  const [members, setMembers] = useState([]);
  const [invitations, setInvitations] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [search, setSearch] = useState("");
  const [filterRole, setFilterRole] = useState("All");
  const [filterStatus, setFilterStatus] = useState("All");

  // Invite Modal State
  const [inviteOpen, setInviteOpen] = useState(false);
  const [inviteEmail, setInviteEmail] = useState("");
  const [inviteRole, setInviteRole] = useState("Recruiter");
  const [inviteLoading, setInviteLoading] = useState(false);
  const [generatedLink, setGeneratedLink] = useState("");

  // Role Info Modal State
  const [infoOpen, setInfoOpen] = useState(false);

  // Edit Role Modal State
  const [roleOpen, setRoleOpen] = useState(false);
  const [selectedMember, setSelectedMember] = useState(null);
  const [newRole, setNewRole] = useState("Recruiter");
  const [roleLoading, setRoleLoading] = useState(false);

  const fetchTeamData = async () => {
    setLoading(true);
    setError("");
    try {
      const [membersRes, invitesRes] = await Promise.all([
        api.get("/api/team/members"),
        api.get("/api/team/invitations")
      ]);
      setMembers(membersRes.data || []);
      setInvitations(invitesRes.data || []);
    } catch (err) {
      console.error(err);
      setError("Failed to fetch team dataset. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchTeamData();
  }, []);

  const handleInvite = async (e) => {
    e.preventDefault();
    if (!inviteEmail.trim()) return;
    setInviteLoading(true);
    setGeneratedLink("");
    try {
      const res = await api.post("/api/team/invitations", {
        email: inviteEmail.trim().toLowerCase(),
        role: inviteRole
      });
      alert(res.data.message || "Invitation created successfully!");
      if (res.data.inviteUrl) {
        // Build absolute invite URL
        const absoluteUrl = `${window.location.origin}${res.data.inviteUrl}`;
        setGeneratedLink(absoluteUrl);
      }
      setInviteEmail("");
      fetchTeamData();
    } catch (err) {
      alert(err.response?.data?.message || "Failed to create invitation");
    } finally {
      setInviteLoading(false);
    }
  };

  const handleCancelInvite = async (id) => {
    if (!window.confirm("Are you sure you want to cancel this pending invitation?")) return;
    try {
      await api.delete(`/api/team/invitations/${id}`);
      alert("Invitation cancelled");
      fetchTeamData();
    } catch (err) {
      alert("Failed to cancel invitation");
    }
  };

  const handleResendInvite = async (id) => {
    try {
      const res = await api.post(`/api/team/invitations/${id}/resend`);
      const absoluteUrl = `${window.location.origin}${res.data.inviteUrl}`;
      alert("Invitation resent! New link generated.");
      // Copy to clipboard or show link
      setInviteOpen(true);
      setGeneratedLink(absoluteUrl);
      fetchTeamData();
    } catch (err) {
      alert("Failed to resend invitation");
    }
  };

  const handleDeactivate = async (membershipId, currentStatus, name) => {
    const nextStatus = currentStatus === "ACTIVE" ? "INACTIVE" : "ACTIVE";
    const msg = nextStatus === "INACTIVE" 
      ? `Deactivate workspace access for "${name}"? They will lose dashboard privileges immediately.`
      : `Reactivate workspace access for "${name}"?`;

    if (!window.confirm(msg)) return;

    try {
      const res = await api.put(`/api/team/members/${membershipId}/status`, { status: nextStatus });
      alert(res.data.message || "Status updated successfully");
      fetchTeamData();
    } catch (err) {
      alert(err.response?.data?.message || "Status update failed");
    }
  };

  const handleRemoveMember = async (membershipId, name) => {
    if (!window.confirm(`Permanently remove team member "${name}" from this organization? Historical activities, feedback, and logs will remain attributed to them.`)) return;
    try {
      const res = await api.delete(`/api/team/members/${membershipId}`);
      alert(res.data.message || "Member removed");
      fetchTeamData();
    } catch (err) {
      alert(err.response?.data?.message || "Failed to remove member");
    }
  };

  const openEditRole = (member) => {
    setSelectedMember(member);
    setNewRole(member.role);
    setRoleOpen(true);
  };

  const handleSaveRole = async () => {
    if (!selectedMember) return;
    setRoleLoading(true);
    try {
      const res = await api.put(`/api/team/members/${selectedMember.membership_id}/role`, { role: newRole });
      alert(res.data.message || "Role updated successfully");
      setRoleOpen(false);
      fetchTeamData();
    } catch (err) {
      alert(err.response?.data?.message || "Failed to update role");
    } finally {
      setRoleLoading(false);
    }
  };

  // Filter lists
  const filteredMembers = members.filter(m => {
    const matchesSearch = 
      m.name?.toLowerCase().includes(search.toLowerCase()) ||
      m.email?.toLowerCase().includes(search.toLowerCase());

    const matchesRole = filterRole === "All" ? true : m.role === filterRole;
    const matchesStatus = filterStatus === "All" ? true : m.status === filterStatus;

    return matchesSearch && matchesRole && matchesStatus;
  });

  // Calculate Metrics
  const activeCount = members.filter(m => m.status === "ACTIVE").length;
  const inactiveCount = members.filter(m => m.status === "INACTIVE").length;
  const adminCount = members.filter(m => m.role === "Admin").length;

  return (
    <AppLayout>
      <div className="container-fluid px-0 text-white text-start">

        {/* HEADER */}
        <div className="d-flex flex-column flex-md-row justify-content-between align-items-md-center gap-3 mb-4">
          <div>
            <h2 className="fw-bold mb-1" style={{ color: "var(--text-primary)" }}>Team Management</h2>
            <p className="text-muted mb-0" style={{ fontSize: "0.9rem" }}>
              Manage team members, configure system authorization roles, and view invitation logs.
            </p>
          </div>

          <div className="d-flex gap-2">
            <Button
              variant="ghost"
              onClick={() => setInfoOpen(true)}
              className="d-flex align-items-center gap-2 text-light"
              style={{ border: "1px solid rgba(255,255,255,0.15)" }}
            >
              <FaInfoCircle /> Role Privileges
            </Button>

            {isAdmin && (
              <Button
                variant="primary"
                onClick={() => {
                  setGeneratedLink("");
                  setInviteOpen(true);
                }}
                className="d-flex align-items-center gap-2"
              >
                <FaUserPlus /> Invite Member
              </Button>
            )}
          </div>
        </div>

        {/* METRICS CARDS */}
        <div className="row g-4 mb-4">
          <div className="col-6 col-md-3">
            <StatCard title="Total Team Members" value={members.length} icon={<FaUsers />} loading={loading} description="Assigned workspace users" />
          </div>
          <div className="col-6 col-md-3">
            <StatCard title="Active Access" value={activeCount} icon={<FaCheckCircle />} loading={loading} description="Active workspace accounts" />
          </div>
          <div className="col-6 col-md-3">
            <StatCard title="Pending Invites" value={invitations.length} icon={<FaClock />} loading={loading} description="Awaiting acceptance" />
          </div>
          <div className="col-6 col-md-3">
            <StatCard title="Admins Assigned" value={adminCount} icon={<FaCrown />} loading={loading} description="Root controllers" />
          </div>
        </div>

        {/* SEARCH AND FILTERS */}
        <Card className="surface-custom border-custom mb-4">
          <CardContent className="p-3">
            <div className="row g-3">
              <div className="col-md-5 position-relative">
                <div className="position-absolute" style={{ left: "22px", top: "20px", color: "var(--text-secondary)" }}>
                  <FaSearch size={14} />
                </div>
                <input
                  type="text"
                  placeholder="Search members by name or email..."
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  className="form-control"
                  style={{ paddingLeft: "38px" }}
                />
              </div>

              <div className="col-md-3">
                <Select
                  value={filterRole}
                  onChange={(e) => setFilterRole(e.target.value)}
                  options={[
                    { value: "All", label: "All Roles" },
                    { value: "Admin", label: "Admin" },
                    { value: "Recruiter", label: "Recruiter" },
                    { value: "Hiring Manager", label: "Hiring Manager" },
                    { value: "Interviewer", label: "Interviewer" }
                  ]}
                />
              </div>

              <div className="col-md-3">
                <Select
                  value={filterStatus}
                  onChange={(e) => setFilterStatus(e.target.value)}
                  options={[
                    { value: "All", label: "All Statuses" },
                    { value: "ACTIVE", label: "Active" },
                    { value: "INACTIVE", label: "Inactive" }
                  ]}
                />
              </div>

              <div className="col-md-1 d-flex">
                <Button 
                  variant="ghost" 
                  onClick={() => {
                    setSearch("");
                    setFilterRole("All");
                    setFilterStatus("All");
                  }}
                  className="w-100 p-0 text-muted"
                  title="Clear Filters"
                >
                  <FaUndo size={14} />
                </Button>
              </div>
            </div>
          </CardContent>
        </Card>

        {/* WORKSPACE MEMBERS TABLE */}
        <div className="row g-4">
          <div className="col-lg-8">
            <Card className="surface-custom border-custom">
              <CardContent className="p-4">
                <h5 className="fw-bold mb-3 d-flex align-items-center gap-2" style={{ color: "var(--text-primary)" }}>
                  <FaUserShield className="text-primary" /> Team Members ({filteredMembers.length})
                </h5>

                {loading ? (
                  <div className="d-flex flex-column gap-2">
                    <Skeleton height="50px" />
                    <Skeleton height="50px" />
                    <Skeleton height="50px" />
                  </div>
                ) : error ? (
                  <div className="text-center p-5 text-danger">{error}</div>
                ) : filteredMembers.length === 0 ? (
                  <div className="text-center py-5 text-muted opacity-75">
                    <FaUsers size={48} className="mb-2" />
                    <p className="mb-0">No team members match your current filters.</p>
                  </div>
                ) : (
                  <div style={{ overflowX: "auto" }}>
                    <table style={{ width: "100%", borderCollapse: "collapse" }}>
                      <thead>
                        <tr style={{ borderBottom: "2px solid var(--border)" }}>
                          <th style={{ padding: "12px", color: "var(--text-secondary)", fontSize: "0.8rem", textTransform: "uppercase", textAlign: "left" }}>Member</th>
                          <th style={{ padding: "12px", color: "var(--text-secondary)", fontSize: "0.8rem", textTransform: "uppercase", textAlign: "left" }}>Role</th>
                          <th style={{ padding: "12px", color: "var(--text-secondary)", fontSize: "0.8rem", textTransform: "uppercase", textAlign: "left" }}>Status</th>
                          <th style={{ padding: "12px", color: "var(--text-secondary)", fontSize: "0.8rem", textTransform: "uppercase", textAlign: "left" }}>Joined</th>
                          {isAdmin && <th style={{ padding: "12px", color: "var(--text-secondary)", fontSize: "0.8rem", textTransform: "uppercase", textAlign: "right" }}>Actions</th>}
                        </tr>
                      </thead>
                      <tbody>
                        {filteredMembers.map((member, index) => (
                          <tr key={member.membership_id || `member-fallback-${index}`} style={{ borderBottom: "1px solid var(--border)" }}>

                            {/* Member Details */}
                            <td style={{ padding: "12px" }}>
                              <div className="d-flex align-items-center gap-2.5">
                                <div 
                                  style={{
                                    width: "36px", height: "36px", borderRadius: "50%",
                                    background: "rgba(99,102,241,0.15)", border: "1px solid rgba(99,102,241,0.3)",
                                    display: "flex", alignItems: "center", justifyContent: "center",
                                    fontWeight: 600, color: "var(--primary)"
                                  }}
                                >
                                  {member.name ? member.name.charAt(0).toUpperCase() : "?"}
                                </div>
                                <div className="d-flex flex-column text-start">
                                  <span className="fw-semibold" style={{ color: "var(--text-primary)", fontSize: "0.92rem" }}>
                                    {member.name} {member.email === currentUserEmail && <small className="text-primary">(You)</small>}
                                  </span>
                                  <small className="text-muted" style={{ fontSize: "0.78rem" }}>{member.email}</small>
                                </div>
                              </div>
                            </td>

                            {/* Role */}
                            <td style={{ padding: "12px" }}>
                              <Badge variant={member.role === "Admin" ? "danger" : member.role === "Recruiter" ? "primary" : "info"}>
                                {member.role}
                              </Badge>
                            </td>

                            {/* Status */}
                            <td style={{ padding: "12px" }}>
                              <span 
                                style={{
                                  fontSize: "0.8rem", fontWeight: 600,
                                  color: member.status === "ACTIVE" ? "#10b981" : "#64748b"
                                }}
                              >
                                {member.status === "ACTIVE" ? "Active" : "Deactivated"}
                              </span>
                            </td>

                            {/* Joined */}
                            <td style={{ padding: "12px", fontSize: "0.85rem", color: "var(--text-secondary)" }}>
                              {member.joined_at ? new Date(member.joined_at).toLocaleDateString() : "—"}
                            </td>

                            {/* Admin Actions */}
                            {isAdmin && (
                              <td style={{ padding: "12px", textAlign: "right" }}>
                                <div className="d-flex align-items-center justify-content-end gap-2">
                                  {/* Change Role */}
                                  <button
                                    onClick={() => openEditRole(member)}
                                    disabled={member.email === currentUserEmail}
                                    style={{
                                      border: "none", background: "rgba(99,102,241,0.1)",
                                      color: "var(--primary)", padding: "6px 10px", borderRadius: "var(--radius-sm)",
                                      fontSize: "0.8rem", cursor: "pointer", opacity: member.email === currentUserEmail ? 0.4 : 1
                                    }}
                                    title="Edit Authorization Role"
                                  >
                                    <FaUserCog /> Role
                                  </button>

                                  {/* Deactivate/Reactivate */}
                                  <button
                                    onClick={() => handleDeactivate(member.membership_id, member.status, member.name)}
                                    disabled={member.email === currentUserEmail}
                                    style={{
                                      border: "none",
                                      background: member.status === "ACTIVE" ? "rgba(239,68,68,0.1)" : "rgba(16,185,129,0.1)",
                                      color: member.status === "ACTIVE" ? "#ef4444" : "#10b981",
                                      padding: "6px 10px", borderRadius: "var(--radius-sm)",
                                      fontSize: "0.8rem", cursor: "pointer", opacity: member.email === currentUserEmail ? 0.4 : 1
                                    }}
                                    title={member.status === "ACTIVE" ? "Suspend workspace access" : "Restore workspace access"}
                                  >
                                    <FaBan /> {member.status === "ACTIVE" ? "Deactivate" : "Activate"}
                                  </button>

                                  {/* Delete */}
                                  <button
                                    onClick={() => handleRemoveMember(member.membership_id, member.name)}
                                    disabled={member.email === currentUserEmail}
                                    style={{
                                      border: "none", background: "rgba(239,68,68,0.15)",
                                      color: "#ef4444", padding: "6px", borderRadius: "var(--radius-sm)",
                                      cursor: "pointer", opacity: member.email === currentUserEmail ? 0.4 : 1
                                    }}
                                    title="Remove permanently"
                                  >
                                    <FaTrash size={12} />
                                  </button>
                                </div>
                              </td>
                            )}

                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                )}
              </CardContent>
            </Card>
          </div>

          {/* INVITATION LOGS */}
          <div className="col-lg-4">
            <Card className="surface-custom border-custom h-100">
              <CardContent className="p-4 d-flex flex-column gap-3">
                <h5 className="fw-bold mb-0 d-flex align-items-center gap-2" style={{ color: "var(--text-primary)" }}>
                  <FaEnvelope className="text-info" /> Invitation Logs
                </h5>

                {loading ? (
                  <Skeleton height="150px" />
                ) : invitations.length === 0 ? (
                  <div className="text-center py-5 text-muted opacity-75 d-flex flex-column align-items-center justify-content-center">
                    <FaEnvelope size={32} className="mb-2 text-muted" />
                    <p className="mb-0" style={{ fontSize: "0.88rem" }}>No pending invitations active.</p>
                  </div>
                ) : (
                  <div className="d-flex flex-column gap-3 overflow-y-auto" style={{ maxHeight: "400px" }}>
                    {invitations.map((invite, index) => {
                      const isExpired = new Date(invite.expires_at) < new Date();
                      return (
                        <div 
                          key={invite.id || `invite-fallback-${index}`} 
                          className="p-3 text-start"
                          style={{
                            background: "rgba(255,255,255,0.03)",
                            border: `1px solid ${isExpired ? "rgba(239,68,68,0.2)" : "rgba(255,255,255,0.08)"}`,
                            borderRadius: "var(--radius-sm)"
                          }}
                        >
                          <div className="d-flex justify-content-between align-items-start gap-2 mb-1.5">
                            <span className="fw-semibold text-truncate" style={{ fontSize: "0.88rem", color: "var(--text-primary)" }}>
                              {invite.email}
                            </span>
                            <Badge variant={isExpired ? "secondary" : "info"} style={{ fontSize: "0.7rem" }}>
                              {invite.role}
                            </Badge>
                          </div>

                          <div className="d-flex flex-column mb-3 text-muted" style={{ fontSize: "0.78rem" }}>
                            <span>Invited by: {invite.invited_by_name || "Admin"}</span>
                            <span>Expires: {new Date(invite.expires_at).toLocaleString()}</span>
                          </div>

                          {isAdmin && (
                            <div className="d-flex justify-content-end gap-2">
                              <button
                                onClick={() => handleResendInvite(invite.id)}
                                style={{
                                  border: "none", background: "rgba(255,255,255,0.08)",
                                  color: "var(--text-primary)", padding: "4px 10px", borderRadius: "var(--radius-sm)",
                                  fontSize: "0.75rem", cursor: "pointer"
                                }}
                              >
                                Resend
                              </button>
                              <button
                                onClick={() => handleCancelInvite(invite.id)}
                                style={{
                                  border: "none", background: "rgba(239,68,68,0.1)",
                                  color: "#ef4444", padding: "4px 10px", borderRadius: "var(--radius-sm)",
                                  fontSize: "0.75rem", cursor: "pointer"
                                }}
                              >
                                Cancel
                              </button>
                            </div>
                          )}
                        </div>
                      );
                    })}
                  </div>
                )}
              </CardContent>
            </Card>
          </div>
        </div>

        {/* INVITE DIALOG MODAL */}
        <Modal isOpen={inviteOpen} onClose={() => setInviteOpen(false)} title="Invite Team Member">
          <form onSubmit={handleInvite} className="d-flex flex-column gap-3 text-start">
            <div>
              <label className="form-label fw-semibold text-muted mb-1" style={{ fontSize: "0.8rem" }}>Email Address</label>
              <Input
                type="email"
                placeholder="developer@company.com"
                value={inviteEmail}
                onChange={(e) => setInviteEmail(e.target.value)}
                required
                disabled={inviteLoading}
              />
            </div>

            <div>
              <label className="form-label fw-semibold text-muted mb-1" style={{ fontSize: "0.8rem" }}>Select Access Role</label>
              <Select
                value={inviteRole}
                onChange={(e) => setInviteRole(e.target.value)}
                options={[
                  { value: "Admin", label: "Admin User (Full workspace & team settings)" },
                  { value: "Recruiter", label: "Recruiter (Create jobs, manage candidates, interview pipeline)" },
                  { value: "Hiring Manager", label: "Hiring Manager (Review assigned candidates & submit feedback)" },
                  { value: "Interviewer", label: "Interviewer (Review assigned interviews & submit scorecards)" }
                ]}
                disabled={inviteLoading}
              />
            </div>

            {generatedLink && (
              <div 
                className="p-3 my-2 text-start"
                style={{
                  background: "rgba(16,185,129,0.1)",
                  border: "1px solid rgba(16,185,129,0.3)",
                  borderRadius: "var(--radius-sm)"
                }}
              >
                <div className="fw-semibold text-success mb-1" style={{ fontSize: "0.85rem" }}>Secure Registration Link Generated:</div>
                <div 
                  className="p-2 mb-2 bg-dark rounded text-break"
                  style={{ fontSize: "0.78rem", border: "1px solid rgba(255,255,255,0.15)", color: "#10b981", userSelect: "all" }}
                >
                  {generatedLink}
                </div>
                <Button 
                  type="button" 
                  variant="ghost" 
                  className="w-100 py-1.5"
                  onClick={() => {
                    navigator.clipboard.writeText(generatedLink);
                    alert("Invite link copied to clipboard!");
                  }}
                  style={{ fontSize: "0.8rem", border: "1px solid rgba(16,185,129,0.4)", color: "#10b981" }}
                >
                  Copy to Clipboard
                </Button>
              </div>
            )}

            <div className="d-flex justify-content-end gap-2.5 mt-3">
              <Button type="button" variant="ghost" onClick={() => setInviteOpen(false)} disabled={inviteLoading}>
                Cancel
              </Button>
              <Button type="submit" variant="primary" loading={inviteLoading}>
                Generate Invite Link
              </Button>
            </div>
          </form>
        </Modal>

        {/* EDIT ROLE MODAL */}
        <Modal isOpen={roleOpen} onClose={() => setRoleOpen(false)} title="Update Authorization Role">
          <div className="text-start">
            <p className="text-muted mb-3" style={{ fontSize: "0.88rem" }}>
              Update workspace permissions for <strong>{selectedMember?.name}</strong> ({selectedMember?.email}).
            </p>

            <div className="mb-4">
              <label className="form-label fw-semibold text-muted mb-1" style={{ fontSize: "0.8rem" }}>Workspace Role</label>
              <Select
                value={newRole}
                onChange={(e) => setNewRole(e.target.value)}
                options={[
                  { value: "Admin", label: "Admin" },
                  { value: "Recruiter", label: "Recruiter" },
                  { value: "Hiring Manager", label: "Hiring Manager" },
                  { value: "Interviewer", label: "Interviewer" }
                ]}
                disabled={roleLoading}
              />
            </div>

            <div className="d-flex justify-content-end gap-2.5">
              <Button variant="ghost" onClick={() => setRoleOpen(false)} disabled={roleLoading}>
                Cancel
              </Button>
              <Button variant="primary" onClick={handleSaveRole} loading={roleLoading}>
                Save Changes
              </Button>
            </div>
          </div>
        </Modal>

        {/* ROLE MATRIX INFO MODAL */}
        <Modal isOpen={infoOpen} onClose={() => setInfoOpen(false)} title="Workspace Role Privileges Matrix">
          <div className="text-start" style={{ overflowX: "auto" }}>
            <table className="table table-dark table-striped text-white" style={{ fontSize: "0.82rem" }}>
              <thead>
                <tr>
                  <th>Permission Privilege</th>
                  <th>Admin</th>
                  <th>Recruiter</th>
                  <th>Hiring Manager</th>
                  <th>Interviewer</th>
                </tr>
              </thead>
              <tbody>
                <tr>
                  <td className="fw-semibold">Invite Team Members / Cancel Invites</td>
                  <td className="text-success fw-bold">Yes</td>
                  <td className="text-danger">No</td>
                  <td className="text-danger">No</td>
                  <td className="text-danger">No</td>
                </tr>
                <tr>
                  <td className="fw-semibold">Change Member Roles / Suspend access</td>
                  <td className="text-success fw-bold">Yes</td>
                  <td className="text-danger">No</td>
                  <td className="text-danger">No</td>
                  <td className="text-danger">No</td>
                </tr>
                <tr>
                  <td className="fw-semibold">Create Requisitions / Edit specs</td>
                  <td className="text-success fw-bold">Yes</td>
                  <td className="text-success fw-bold">Yes</td>
                  <td className="text-danger">No</td>
                  <td className="text-danger">No</td>
                </tr>
                <tr>
                  <td className="fw-semibold">View Workspace Jobs</td>
                  <td className="text-success fw-bold">All</td>
                  <td className="text-success fw-bold">All</td>
                  <td className="text-info fw-bold">Assigned Only</td>
                  <td className="text-danger">No</td>
                </tr>
                <tr>
                  <td className="fw-semibold">Manage Applications / Pipeline Stages</td>
                  <td className="text-success fw-bold">Yes</td>
                  <td className="text-success fw-bold">Yes</td>
                  <td className="text-info fw-bold">Limited/Review</td>
                  <td className="text-danger">No</td>
                </tr>
                <tr>
                  <td className="fw-semibold">Schedule Candidates & Interviews</td>
                  <td className="text-success fw-bold">Yes</td>
                  <td className="text-success fw-bold">Yes</td>
                  <td className="text-danger">No</td>
                  <td className="text-danger">No</td>
                </tr>
                <tr>
                  <td className="fw-semibold">Submit Feedback Scorecard</td>
                  <td className="text-success fw-bold">Yes</td>
                  <td className="text-success fw-bold">Yes</td>
                  <td className="text-success fw-bold">Yes</td>
                  <td className="text-success fw-bold">Assigned Only</td>
                </tr>
                <tr>
                  <td className="fw-semibold">View general Workspace Analytics</td>
                  <td className="text-success fw-bold">Yes</td>
                  <td className="text-success fw-bold">Yes</td>
                  <td className="text-danger">No</td>
                  <td className="text-danger">No</td>
                </tr>
              </tbody>
            </table>
            <div className="d-flex justify-content-end mt-3">
              <Button variant="primary" onClick={() => setInfoOpen(false)}>
                Dismiss
              </Button>
            </div>
          </div>
        </Modal>

      </div>
    </AppLayout>
  );
}

export default Team;

import React, { useEffect, useState } from "react";
import api from "../services/api";
import AppLayout from "../components/layout/AppLayout";
import StatCard from "../components/ui/StatCard";
import { Card, CardContent } from "../components/ui/Card";
import Badge from "../components/ui/Badge";
import Button from "../components/ui/Button";
import Select from "../components/ui/Select";
import Modal from "../components/ui/Modal";
import Skeleton from "../components/ui/Skeleton";
import EmptyState from "../components/feedback/EmptyState";
import {
  FaTrophy,
  FaSearch,
  FaFileDownload,
  FaRobot,
  FaCheck,
  FaTimes,
  FaUserCircle,
  FaExclamationTriangle,
  FaCheckCircle,
  FaExternalLinkAlt,
  FaExchangeAlt
} from "react-icons/fa";

function TopCandidates() {
  const [jobs, setJobs] = useState([]);
  const [candidates, setCandidates] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");

  // Job selection
  const [selectedJobId, setSelectedJobId] = useState("All");

  // Selection for comparison (up to 3 candidates)
  const [selectedIds, setSelectedIds] = useState([]);
  const [comparisonOpen, setComparisonOpen] = useState(false);
  const [comparedCandidates, setComparedCandidates] = useState([]);

  // Pipeline update status
  const [updatingId, setUpdatingId] = useState(null);

  // Rejection modal states
  const [rejectOpen, setRejectOpen] = useState(false);
  const [rejectionReasonText, setRejectionReasonText] = useState("");
  const [rejectingCandidateId, setRejectingCandidateId] = useState(null);

  // Load jobs and candidate rankings
  const loadData = async () => {
    setLoading(true);
    try {
      const [jobsRes, hrCandidatesRes] = await Promise.all([
        api.get("/api/job-descriptions"),
        api.get("/api/hr/all-candidates")
      ]);
      setJobs(jobsRes.data || []);
      setCandidates(hrCandidatesRes.data || []);

      // Auto-select first job if present
      if (jobsRes.data?.length > 0) {
        setSelectedJobId(jobsRes.data[0].jdId);
      }
    } catch (err) {
      console.warn("Failed to load ranking dashboard metrics:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  // Filter candidates based on selected job requisition and search query
  const getFilteredCandidates = () => {
    let list = [...candidates];

    // 1. Job Requisition Filter
    if (selectedJobId !== "All") {
      list = list.filter(c => {
        // Since we joined applications with job_descriptions to fetch candidates,
        // we can filter candidates by comparing their applied job requisitions or match keys
        // If there's an explicit match, filter it, otherwise check job title
        const jobObj = jobs.find(j => Number(j.jdId) === Number(selectedJobId));
        return jobObj ? c.job_title === jobObj.title : true;
      });
    }

    // 2. Search Query
    if (search.trim()) {
      const query = search.toLowerCase();
      list = list.filter(
        c =>
          c.name?.toLowerCase().includes(query) ||
          c.email?.toLowerCase().includes(query) ||
          c.job_title?.toLowerCase().includes(query)
      );
    }

    // 3. Deterministic AI Ranking Sort:
    // 1. match_score DESC
    // 2. skills_score DESC
    // 3. experience_score DESC
    // 4. education_score DESC
    // 5. stable tie-breaker (candidate ID DESC)
    list.sort((a, b) => {
      const scoreA = a.match_score !== null ? a.match_score : -1;
      const scoreB = b.match_score !== null ? b.match_score : -1;

      if (scoreB !== scoreA) return scoreB - scoreA;

      const skillsA = a.skills_score || 0;
      const skillsB = b.skills_score || 0;
      if (skillsB !== skillsA) return skillsB - skillsA;

      const expA = a.experience_score || 0;
      const expB = b.experience_score || 0;
      if (expB !== expA) return expB - expA;

      const eduA = a.education_score || 0;
      const eduB = b.education_score || 0;
      if (eduB !== eduA) return eduB - eduA;

      return b.id - a.id; // stable ID tie-breaker
    });

    return list;
  };

  const sortedCandidates = getFilteredCandidates();

  // Statistics counters
  const totalApplicants = sortedCandidates.length;
  const screenedCount = sortedCandidates.filter(c => c.match_score !== null).length;
  const unscreenedCount = totalApplicants - screenedCount;
  const strongMatches = sortedCandidates.filter(c => (c.match_score || 0) >= 75).length;

  const averageMatchScore = screenedCount > 0 
    ? Math.round(sortedCandidates.reduce((sum, c) => sum + (c.match_score || 0), 0) / screenedCount) 
    : 0;

  // Handle Checkbox Selection
  const handleCheckboxChange = (id) => {
    setSelectedIds(prev => {
      if (prev.includes(id)) {
        return prev.filter(item => item !== id);
      }
      if (prev.length >= 3) {
        alert("You can select up to 3 candidates maximum for side-by-side comparison.");
        return prev;
      }
      return [...prev, id];
    });
  };

  // Launch Candidate Comparison Sheet
  const handleOpenComparison = () => {
    if (selectedIds.length < 2) {
      alert("Please select at least 2 candidates to compare.");
      return;
    }
    const compared = candidates.filter(c => selectedIds.includes(c.id));
    setComparedCandidates(compared);
    setComparisonOpen(true);
  };

  // Inline assessment actions
  const handleShortlist = async (id) => {
    setUpdatingId(id);
    try {
      await api.put(`/api/applications/shortlist/${id}`);
      alert("Candidate Shortlisted");
      loadData();

      // Update compared candidate records if comparison sheet is open
      setComparedCandidates(prev => prev.map(c => c.id === id ? { ...c, status: "Shortlisted" } : c));
    } catch (err) {
      alert("Shortlist action failed");
    } finally {
      setUpdatingId(null);
    }
  };

  const triggerReject = (id) => {
    setRejectingCandidateId(id);
    setRejectionReasonText("");
    setRejectOpen(true);
  };

  const handleConfirmReject = async () => {
    if (!rejectingCandidateId) return;
    setUpdatingId(rejectingCandidateId);
    try {
      await api.put(`/api/applications/reject/${rejectingCandidateId}`, { reason: rejectionReasonText.trim() });
      alert("Candidate Rejected");
      setRejectOpen(false);
      loadData();

      // Update compared candidate records if comparison sheet is open
      setComparedCandidates(prev => prev.map(c => c.id === rejectingCandidateId ? { ...c, status: "Rejected" } : c));
    } catch (err) {
      alert("Rejection action failed");
    } finally {
      setUpdatingId(null);
    }
  };

  // Score badge helper
  const getScoreBadgeClass = (score) => {
    if (score >= 75) return "success";
    if (score >= 50) return "info";
    return "danger";
  };

  // Pipeline Badge helper
  const getStatusBadge = (status) => {
    if (status === "Shortlisted") return <Badge variant="success">Shortlisted</Badge>;
    if (status === "Rejected") return <Badge variant="danger">Rejected</Badge>;
    return <Badge variant="warning">Pending Review</Badge>;
  };

  const selectedJob = jobs.find(j => Number(j.jdId) === Number(selectedJobId));

  return (
    <AppLayout>
      <div className="container-fluid px-0 text-white text-start">

        {/* HEADER */}
        <div className="mb-4">
          <h2 className="fw-bold mb-1" style={{ color: "var(--text-primary)" }}>AI Candidate Ranking</h2>
          <p className="text-muted mb-0" style={{ fontSize: "0.9rem" }}>
            Rank and evaluate candidate applications side-by-side using multi-component suitability metrics.
          </p>
          <div className="alert border border-warning border-opacity-15 bg-warning bg-opacity-5 p-2.5 mt-2 mb-0 d-flex align-items-center gap-2" style={{ fontSize: "0.85rem" }}>
            <FaExclamationTriangle className="text-warning-light" />
            <span className="text-muted">
              AI-assisted rankings summarize job-related candidate analysis and are intended to support, not replace, recruiter judgment.
            </span>
          </div>
        </div>

        {/* WORKFLOW AND REQUISITION SELECTION */}
        <div className="row g-4 mb-4">
          <div className="col-md-4">
            <Card className="surface-custom border-custom h-100">
              <CardContent className="p-3.5">
                <label className="form-label-custom mb-1">Target Job Requisition</label>
                <Select
                  value={selectedJobId}
                  onChange={(e) => { setSelectedJobId(e.target.value); setSelectedIds([]); }}
                  options={[
                    { value: "All", label: "All Job Requisitions" },
                    ...jobs.map(j => ({ value: j.jdId, label: j.title }))
                  ]}
                  className="mb-0"
                />
              </CardContent>
            </Card>
          </div>

          <div className="col-md-8">
            {/* RANKING METRICS */}
            <div className="row g-3">
              <div className="col-6 col-md-3">
                <StatCard title="Total Applicants" value={totalApplicants} icon={<FaUserCircle />} loading={loading} description="Job-specific applications" />
              </div>
              <div className="col-6 col-md-3">
                <StatCard title="AI Screened" value={screenedCount} icon={<FaRobot />} loading={loading} description="Processed profiles" />
              </div>
              <div className="col-6 col-md-3">
                <StatCard title="Strong Matches" value={strongMatches} icon={<FaTrophy />} loading={loading} description="Fit score >= 75%" />
              </div>
              <div className="col-6 col-md-3">
                <StatCard title="Average Fit" value={`${averageMatchScore}%`} icon={<FaCheckCircle />} loading={loading} description="Average compatibility" />
              </div>
            </div>
          </div>
        </div>

        {/* FLOATING ACTION TOOLBAR */}
        {selectedIds.length >= 2 && (
          <div className="alert bg-primary bg-opacity-15 border border-primary border-opacity-25 p-3 mb-4 d-flex justify-content-between align-items-center rounded">
            <div className="d-flex align-items-center gap-2">
              <FaExchangeAlt className="text-primary-light" />
              <span><strong>{selectedIds.length}</strong> candidate profiles selected for side-by-side analysis.</span>
            </div>
            <div className="d-flex gap-2">
              <Button variant="ghost" size="sm" onClick={() => setSelectedIds([])}>Clear</Button>
              <Button variant="primary" size="sm" onClick={handleOpenComparison}>Compare Candidates</Button>
            </div>
          </div>
        )}

        {/* SEARCH AND FILTERS */}
        <Card className="surface-custom border-custom mb-4">
          <CardContent className="p-3.5 d-flex gap-3 align-items-center justify-content-between">
            <div className="position-relative w-100" style={{ maxWidth: "350px" }}>
              <FaSearch className="position-absolute text-muted" style={{ left: "12px", top: "14px" }} />
              <input
                type="text"
                className="form-control ps-5"
                placeholder="Search candidate name, email, role..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
              />
            </div>
            <div className="text-muted" style={{ fontSize: "0.85rem" }}>
              * Rankings are calculated deterministically across skills, experience, and education vectors.
            </div>
          </CardContent>
        </Card>

        {/* RANKING LIST TABLE */}
        {loading ? (
          <Card className="surface-custom border-custom">
            <CardContent className="p-4">
              <Skeleton variant="rect" width="100%" height={30} className="mb-2" />
              <Skeleton variant="rect" width="100%" height={50} className="mb-2" />
              <Skeleton variant="rect" width="100%" height={50} />
            </CardContent>
          </Card>
        ) : sortedCandidates.length === 0 ? (
          <EmptyState title="No Candidates Found" description="Try selecting another requisition or adjust search queries." />
        ) : (
          <Card className="surface-custom border-custom">
            <CardContent className="p-0">
              <div className="table-responsive">
                <table className="table table-hover align-middle mb-0">
                  <thead>
                    <tr>
                      <th style={{ width: "50px" }}>Select</th>
                      <th style={{ width: "70px" }}>Rank</th>
                      <th>Candidate Details</th>
                      <th>Applied Role</th>
                      <th>Overall Fit</th>
                      <th style={{ width: "100px" }}>Skills</th>
                      <th style={{ width: "100px" }}>Exp</th>
                      <th style={{ width: "100px" }}>Edu</th>
                      <th>Status</th>
                      <th className="text-end">Recommendation</th>
                    </tr>
                  </thead>
                  <tbody>
                    {sortedCandidates.map((candidate, index) => {
                      const isChecked = comparedCandidates.some(c => c.id === candidate.id);
                      return (
                        <tr key={candidate.id || `candidate-fallback-${index}`} className={isChecked ? "table-active" : ""}>
                          <td>
                            <input
                              type="checkbox"
                              className="form-check-input"
                              checked={isChecked}
                              disabled={!isChecked && selectedIds.length >= 3 && candidate.match_score !== null}
                              onChange={() => handleCheckboxChange(candidate.id)}
                            />
                          </td>
                          <td>
                            <span className="fw-bold text-secondary-custom">#{index + 1}</span>
                          </td>
                          <td>
                            <div className="fw-bold text-white">{candidate.name}</div>
                            <small className="text-muted">{candidate.email}</small>
                          </td>
                          <td>{candidate.job_title || "Unspecified"}</td>
                          <td>
                            {candidate.match_score !== null ? (
                              <div className="d-flex align-items-center gap-2">
                                <div className="progress flex-grow-1" style={{ height: "6px", minWidth: "80px" }}>
                                  <div className={`progress-bar bg-${getScoreBadgeClass(candidate.match_score)}`} style={{ width: `${candidate.match_score}%` }}></div>
                                </div>
                                <span className="fw-semibold text-white" style={{ fontSize: "0.85rem" }}>{candidate.match_score}%</span>
                              </div>
                            ) : (
                              <span className="text-muted small">Not Analyzed</span>
                            )}
                          </td>
                          <td>{candidate.skills_score !== null ? `${candidate.skills_score}%` : "—"}</td>
                          <td>{candidate.experience_score !== null ? `${candidate.experience_score}%` : "—"}</td>
                          <td>{candidate.education_score !== null ? `${candidate.education_score}%` : "—"}</td>
                          <td>{getStatusBadge(candidate.status)}</td>
                          <td className="text-end">
                            {candidate.recommendation ? (
                              <Badge variant={getScoreBadgeClass(candidate.match_score)}>{candidate.recommendation.split(" - ")[0]}</Badge>
                            ) : (
                              <span className="text-muted small">Awaiting Screening</span>
                            )}
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            </CardContent>
          </Card>
        )}

        {/* CANDIDATE SIDE-BY-SIDE COMPARISON MODAL */}
        {comparisonOpen && comparedCandidates.length >= 2 && (
          <Modal
            isOpen={comparisonOpen}
            onClose={() => setComparisonOpen(false)}
            title="Candidate Side-by-Side Comparison"
            size="xl"
            footer={
              <div className="w-100 d-flex justify-content-between">
                <Button variant="ghost" onClick={() => setComparisonOpen(false)}>Close Wizard</Button>
                <span className="text-muted small align-self-center">* Verify certifications and references manually prior to offer bookings.</span>
              </div>
            }
          >
            <div className="table-responsive text-white">
              <table className="table table-bordered align-middle text-start mb-0">
                <thead>
                  <tr className="bg-dark bg-opacity-30">
                    <th style={{ width: "180px", color: "var(--primary-light)", fontWeight: "bold" }}>Metrics Criteria</th>
                    {comparedCandidates.map((c, index) => (
                      <th key={c.id || `c-fallback-${index}`} style={{ minWidth: "220px" }}>
                        <div className="d-flex align-items-center gap-2">
                          <FaUserCircle size={32} className="text-secondary" />
                          <div>
                            <div className="fw-bold text-white" style={{ fontSize: "0.95rem" }}>{c.name}</div>
                            <small className="text-muted d-block">{c.email}</small>
                          </div>
                        </div>
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {/* Pipeline Action Row */}
                  <tr>
                    <td><strong>Decisions</strong></td>
                    {comparedCandidates.map((c, index) => (
                      <td key={c.id || `c-fallback-${index}`}>
                        <div className="d-flex gap-1.5 flex-wrap">
                          <Button
                            variant="primary"
                            size="sm"
                            className="py-1"
                            disabled={c.status === "Shortlisted" || updatingId === c.id}
                            onClick={() => handleShortlist(c.id)}
                          >
                            Shortlist
                          </Button>
                          <Button
                            variant="destructive"
                            size="sm"
                            className="py-1"
                            disabled={c.status === "Rejected" || updatingId === c.id}
                            onClick={() => triggerReject(c.id)}
                          >
                            Reject
                          </Button>
                        </div>
                      </td>
                    ))}
                  </tr>

                  {/* Recommendation status */}
                  <tr>
                    <td><strong>Recommendation</strong></td>
                    {comparedCandidates.map((c, index) => (
                      <td key={c.id || `c-fallback-${index}`}>
                        <Badge variant={getScoreBadgeClass(c.match_score)}>
                          {c.recommendation || "Pending Review"}
                        </Badge>
                      </td>
                    ))}
                  </tr>

                  {/* Overall Fit */}
                  <tr>
                    <td><strong>Overall Match Score</strong></td>
                    {comparedCandidates.map((c, index) => (
                      <td key={c.id || `c-fallback-${index}`}>
                        <div className="d-flex align-items-center gap-2">
                          <div
                            className={`d-flex align-items-center justify-content-center rounded-circle border border-3 border-${getScoreBadgeClass(c.match_score)}`}
                            style={{ width: "48px", height: "48px", fontWeight: "bold", fontSize: "0.95rem" }}
                          >
                            {c.match_score}%
                          </div>
                          <span className="text-muted small">Suitability Fit</span>
                        </div>
                      </td>
                    ))}
                  </tr>

                  {/* Component breakdowns */}
                  <tr>
                    <td><strong>Skills Match</strong></td>
                    {comparedCandidates.map((c, index) => (
                      <td key={c.id || `c-fallback-${index}`}>
                        <strong className="text-white">{c.skills_score || 0}%</strong>
                        <div className="progress mt-1" style={{ height: "4px" }}>
                          <div className="progress-bar bg-info" style={{ width: `${c.skills_score || 0}%` }}></div>
                        </div>
                      </td>
                    ))}
                  </tr>

                  <tr>
                    <td><strong>Experience Match</strong></td>
                    {comparedCandidates.map((c, index) => (
                      <td key={c.id || `c-fallback-${index}`}>
                        <strong className="text-white">{c.experience_score || 0}%</strong>
                        <div className="progress mt-1" style={{ height: "4px" }}>
                          <div className="progress-bar bg-success" style={{ width: `${c.experience_score || 0}%` }}></div>
                        </div>
                      </td>
                    ))}
                  </tr>

                  <tr>
                    <td><strong>Education Match</strong></td>
                    {comparedCandidates.map((c, index) => (
                      <td key={c.id || `c-fallback-${index}`}>
                        <strong className="text-white">{c.education_score || 0}%</strong>
                        <div className="progress mt-1" style={{ height: "4px" }}>
                          <div className="progress-bar bg-primary" style={{ width: `${c.education_score || 0}%` }}></div>
                        </div>
                      </td>
                    ))}
                  </tr>

                  {/* Matched Skills */}
                  <tr>
                    <td><strong>Matched Skills</strong></td>
                    {comparedCandidates.map((c, index) => (
                      <td key={c.id || `c-fallback-${index}`}>
                        <div className="d-flex flex-wrap gap-1">
                          {c.matched_skills ? (
                            c.matched_skills.split(",").map((s, idx) => (
                              <Badge key={idx} variant="success" style={{ fontSize: "0.68rem" }}>{s.trim()}</Badge>
                            ))
                          ) : (
                            <span className="text-muted small">None parsed</span>
                          )}
                        </div>
                      </td>
                    ))}
                  </tr>

                  {/* Missing Skills */}
                  <tr>
                    <td><strong>Missing Skill Gaps</strong></td>
                    {comparedCandidates.map((c, index) => (
                      <td key={c.id || `c-fallback-${index}`}>
                        <div className="d-flex flex-wrap gap-1">
                          {c.missing_skills ? (
                            c.missing_skills.split(",").map((s, idx) => (
                              <Badge key={idx} variant="danger" style={{ fontSize: "0.68rem" }}>{s.trim()}</Badge>
                            ))
                          ) : (
                            <span className="text-muted small">None missing</span>
                          )}
                        </div>
                      </td>
                    ))}
                  </tr>

                  {/* Key Strengths */}
                  <tr>
                    <td><strong>Key Strengths</strong></td>
                    {comparedCandidates.map((c, index) => (
                      <td key={c.id || `c-fallback-${index}`}>
                        <ul className="ps-3 mb-0 text-muted" style={{ fontSize: "0.8rem", lineHeight: 1.4 }}>
                          {c.candidate_strengths?.split(" | ").map((s, idx) => (
                            <li key={idx} className="mb-0.5">{s}</li>
                          ))}
                        </ul>
                      </td>
                    ))}
                  </tr>

                  {/* Considerations */}
                  <tr>
                    <td><strong>Review Considerations</strong></td>
                    {comparedCandidates.map((c, index) => (
                      <td key={c.id || `c-fallback-${index}`}>
                        <ul className="ps-3 mb-0 text-muted" style={{ fontSize: "0.8rem", lineHeight: 1.4 }}>
                          {c.review_considerations?.split(" | ").map((con, idx) => (
                            <li key={idx} className="mb-0.5">{con}</li>
                          ))}
                        </ul>
                      </td>
                    ))}
                  </tr>

                  {/* Resume Download */}
                  <tr>
                    <td><strong>Document</strong></td>
                    {comparedCandidates.map((c, index) => (
                      <td key={c.id || `c-fallback-${index}`}>
                        {c.resume_file ? (
                          <a
                            href={`${api.defaults.baseURL || ""}/uploads/${c.resume_file}`}
                            target="_blank"
                            rel="noreferrer"
                            className="btn btn-outline-danger btn-sm py-1 d-inline-flex align-items-center gap-1.5"
                            style={{ textDecoration: "none" }}
                          >
                            <FaFileDownload /> Resume PDF
                          </a>
                        ) : (
                          <span className="text-muted small">No file</span>
                        )}
                      </td>
                    ))}
                  </tr>
                </tbody>
              </table>
            </div>
          </Modal>
        )}

        {/* REJECTION CONFIRM DIALOG */}
        {rejectOpen && (
          <Modal
            isOpen={rejectOpen}
            onClose={() => setRejectOpen(false)}
            title="Log Rejection Reason"
            size="sm"
            footer={
              <>
                <Button variant="ghost" onClick={() => setRejectOpen(false)}>Cancel</Button>
                <Button variant="destructive" onClick={handleConfirmReject}>
                  Confirm Rejection
                </Button>
              </>
            }
          >
            <div className="text-start">
              <p className="text-muted mb-3" style={{ fontSize: "0.9rem" }}>
                Enter the reason for rejecting this candidate. (Rejection reasons are logged for recruitment tracking).
              </p>
              <label htmlFor="rejectionReasonRank" className="form-label-custom mb-1">Rejection Reason</label>
              <textarea
                id="rejectionReasonRank"
                className="form-control"
                rows="3"
                placeholder="e.g. Technical assessment criteria not met"
                value={rejectionReasonText}
                onChange={(e) => setRejectionReasonText(e.target.value)}
              />
            </div>
          </Modal>
        )}

      </div>
    </AppLayout>
  );
}

export default TopCandidates;
